insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 1, 60000, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0, 1, 190804, 'カリン', 0, 1, 1);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60000, '今日の運勢は姫吉！\u3000あらゆる運気が最大を示しています！\u3000\u3000\u3000今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！', 0, 0, 0, '', 0, 2, 2);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60000, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0, 0, 0, '', 0, 2, 3);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 2, 60000, '今日の運勢は姫吉！\u3000その高い運気はまさにショーグンの如く！\u3000その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！', 0, 0, 0, '', 0, 2, 4);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60000, '今日の運勢は大吉！\u3000運気がどんどん高まっています！\u3000\u3000\u3000\u3000\u3000何をやっても、最大効率で素晴らしい結果になりますよ♪', 0, 0, 0, '', 0, 2, 5);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60000, '今日の運勢は大吉！\u3000なにをやっても上手くいって大活躍！\u3000\u3000\u3000そんな素敵なあなたを見て、後ろから誰かが……クスクス♪', 0, 0, 0, '', 0, 2, 6);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 2, 60000, '今日の運勢は大吉！\u3000運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！\u3000目指せヒデサ……ではなく秀才！', 0, 0, 0, '', 0, 2, 7);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60000, '今日の運勢は中吉！\u3000商売運が上がってきています！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムはたいやき！\u3000和菓子パワーで売上アップです！', 0, 0, 0, '', 0, 2, 8);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60000, '今日の運勢は中吉！\u3000旅行運がぐんぐんと上昇中♪\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、あの「マホマホ王国」にだって行けるかも♪', 0, 0, 0, '', 0, 2, 9);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60000, '今日の運勢は中吉！\u3000仕事運が急上昇中です！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！', 0, 0, 0, '', 0, 2, 10);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60000, '今日の運勢は中吉！\u3000チャンスを待つと良い結果に！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムのプリンを食べて、運を呼び込みましょう！', 0, 0, 0, '', 0, 2, 11);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 2, 60000, '今日の運勢は中吉！\u3000運気が着々と上昇中！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪', 0, 0, 0, '', 0, 2, 12);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60000, '今日の運勢は小吉！\u3000早朝に幸運の兆しあり！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪', 0, 0, 0, '', 0, 2, 13);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60000, '今日の運勢は小吉！\u3000運気上昇中ですが、上がるまでが要注意！\u3000ラッキーアニマルは熊！\u3000本当の家族のように守ってくれるかも♪', 0, 0, 0, '', 0, 2, 14);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60000, '今日の運勢は小吉！\u3000外に出てゆっくり過ごすと運気が上昇！\u3000\u3000ラッキースポットは牧場。面白い出会いがありそうです♪', 0, 0, 0, '', 0, 2, 15);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60000, '今日の運勢は小吉！\u3000運気は高いけども、ハプニングには注意！\u3000出かけた先で、「ふしんしゃ」扱いされてしまうかも……', 0, 0, 0, '', 0, 2, 16);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 2, 60000, '今日の運勢は小吉！\u3000根を詰めずにリラックスすると運気向上！\u3000ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪', 0, 0, 0, '', 0, 2, 17);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60000, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0, 2, 190804, 'カリン', 0, 3, 18);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60000, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0, 3, 190804, 'カリン', 7, 3, 19);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'キミと出会ってもう\\n1年もたつんだね！\\nう～ん、いつも\\n寝てばっかりだから、', 0, 1, 101201, 'ハツネ', 1, 0, 20);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '少しでも\\n寝る時間を減らして\\nキミと一緒にいる\\n時間増やしたいなぁ♪', 0, 2, 101201, 'ハツネ', 1, 0, 21);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あなたと知り合ってから\\nもう1年…\\n時がたつのは\\n早いですね', 0, 1, 103801, 'シオリ', 1, 1, 22);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '来年も、\\n一緒にいられたら…\\nうれしいな', 0, 2, 103801, 'シオリ', 1, 1, 23);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あなたと一緒にいるようになって、\\nもう1年ですか…', 0, 1, 103601, 'キョウカ', 2, 0, 24);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '最初の頃よりも、頼もしく\\nなりましたね。私はどうですか？\\n成長していますか？', 0, 2, 103601, 'キョウカ', 2, 0, 25);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'おにいちゃんとあってから、\\n1年たったよ～！', 0, 1, 102001, 'ミミ', 2, 1, 26);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'ミミね、おにいちゃんと\\nいっぱい遊べてたのしかったな～♪\\nこれからもずっと\\nいっしょにいてね～！', 0, 2, 102001, 'ミミ', 2, 1, 27);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'にいちゃんがミソギのイタズラに\\n引っかかり続けてもう1年かぁ', 0, 1, 100401, 'ミソギ', 2, 2, 28);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '…これからもいっぱいミソギと\\n遊んでね、にいちゃん！', 0, 2, 100401, 'ミソギ', 2, 2, 29);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'もう王子はんと会うてから\\n1年ぐらいたつそうどすえ\\n早いもんやなあ', 0, 1, 101001, 'マホ', 3, 0, 30);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'このままやと、\\nうちもあっという間に\\n干からびてしまいそうどすえ\\nなーんてな。うふふ', 0, 2, 101001, 'マホ', 3, 0, 31);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'お主と会って早1年じゃな\\nこれからも存分に尽くすがよい', 0, 1, 104401, 'イリヤ', 3, 1, 32);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'わらわもたまには、お主の献身に\\n報いてやらぬでもない♪', 0, 2, 104401, 'イリヤ', 3, 1, 33);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'もう、キミと出会って結構な時間が\\nたつさ～。でも、私たちの旅は\\nまだまだ始まったばかりさ～！', 0, 1, 101701, 'カオリ', 3, 2, 34);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'これからも、どうぞよろしく\\nお願いするさ～！', 0, 2, 101701, 'カオリ', 3, 2, 35);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あんたと出会ってからもうそんなに\\nたつのね～', 0, 1, 102801, 'サレン', 4, 0, 36);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あっという間だったって感じるほど\\n楽しかったわ！\\nこれからも一緒に頑張りましょ！', 0, 2, 102801, 'サレン', 4, 0, 37);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '出会ってから1年間、ずっと\\nご迷惑をかけっぱなしで、\\nすみません…', 0, 1, 102501, 'スズメ', 4, 1, 38);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'これからはもっと頑張りますから\\n見ていてくださいね\\nできれば…\\n今までよりも、私の近くで♪', 0, 2, 102501, 'スズメ', 4, 1, 39);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '振り返れば、今までいろんなことが\\nあったにゃあ…', 0, 1, 104601, 'タマキ', 5, 0, 40);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'これからも、二人でたくさんの\\n思い出をがっぽり作っていく\\nにゃー！', 0, 2, 104601, 'タマキ', 5, 0, 41);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'キミとの師弟関係も、\\nもう1年なのね…\\nでもキミに教えることは、', 0, 1, 104801, 'ミフユ', 5, 1, 42);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'まだまだいっぱいあるわ\\nこれからも、\\nしっかりついて来てね！', 0, 2, 104801, 'ミフユ', 5, 1, 43);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あなたさまと出会ってもう1年…', 0, 1, 103201, 'アキノ', 6, 0, 44);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '光陰矢のごとし、とはまさに\\nこのことですわ。…思い出は決して\\nお金では買えませんわね', 0, 2, 103201, 'アキノ', 6, 0, 45);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'ダメな私を1年間も見捨てないで\\nくれて、本当にありがとう', 0, 1, 103401, 'ユカリ', 6, 1, 46);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '情けないところいっぱいみせるかも\\nしれないけど、これからも一緒に\\nいてくれると、うれしいな', 0, 2, 103401, 'ユカリ', 6, 1, 47);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'オマエと出会ってもう1年か\\nまさかこのワタシの結婚相手に\\nなろうとはな…', 0, 1, 107101, 'クリスティーナ', 7, 0, 48);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'ともかくこれからも\\n愉しませてくれよ☆', 0, 2, 107101, 'クリスティーナ', 7, 0, 49);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '君と出会ってからもう1年か。\\n以前と比べて私の表情もいくらか\\n柔らかくなった気がするんだが、\\nどうだろう？', 0, 1, 104701, 'ジュン', 7, 1, 50);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '見えないから分からないって？\\nそれもそうだな…', 0, 2, 104701, 'ジュン', 7, 1, 51);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'もう1年たったみたいだね\\nあなたをからかってばかりだった\\nけど、楽しかった♪', 0, 1, 103701, 'トモ', 8, 0, 52);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'これからもよろしくね！', 0, 2, 103701, 'トモ', 8, 0, 53);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '出会って、もう1年たっちゃった\\nんスね。なんだか意外ッス', 0, 1, 100501, 'マツリ', 8, 1, 54);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '毎日楽しくて、あっという間に過ぎ\\nちゃったみたいなんスよね\\nこれからも一緒に悪と戦うッス！', 0, 2, 100501, 'マツリ', 8, 1, 55);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'オマエと会って1年なの！\\n全然成仏もできなかったし、', 0, 1, 100701, 'ミヤコ', 9, 0, 56);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '生き返りもしなかったけど、\\nすごく楽しかったの～♪\\nオマエとプリンがあれば、\\nミヤコはハッピーなの～♪', 0, 2, 100701, 'ミヤコ', 9, 0, 57);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あなたと出会って1年なんですね\\nでも、私の占いでは、私とあなたは', 0, 1, 103101, 'シノブ', 9, 1, 58);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '来年も再来年も一緒にいるようです\\nふふ、よろしくお願いしますね', 0, 2, 103101, 'シノブ', 9, 1, 59);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '貴様が閃光のシグルドとして覚醒し\\nもう1年か…。これからも我らの\\n長き戦いに終わりはないが、', 0, 1, 100901, 'アンナ', 10, 0, 60);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'それでも貴様となら…\\n添い遂げる覚悟はできているぞ！', 0, 2, 100901, 'アンナ', 10, 0, 61);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '君と出会ってもう1年だって！\\n早いねー！', 0, 1, 101301, 'ナナカ', 10, 1, 62);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'これからも最強のバディタッグで\\n大活躍だー！\\n頼りにしてるよ、相棒！', 0, 2, 101301, 'ナナカ', 10, 1, 63);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '1年たつのって、あっという間ね\\nまだまだ君の知らない部分が\\nたくさんあるし…', 0, 1, 105101, 'ミツキ', 11, 0, 64);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'これからも、いろんなところを\\n調べさせてね？', 0, 2, 105101, 'ミツキ', 11, 0, 65);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'お前さんと出会ってもう1年か\\n助太刀するつもりが', 0, 1, 105601, 'ルカ', 11, 1, 66);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '逆に助けられたりもしたね\\nこれからもよろしく頼むよ！', 0, 2, 105601, 'ルカ', 11, 1, 67);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '早いものですわね、あなた様と\\nお会いして、もう1年…', 0, 1, 102701, 'エリコ', 11, 2, 68);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あなた様といると、時があっと\\nいう間に過ぎてしまいます\\n時間を止める研究をしなくては\\nいけませんね…', 0, 2, 102701, 'エリコ', 11, 2, 69);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'お兄ちゃんと会ってから、もう、\\n1年なんだね。私、少しは\\nお姉ちゃんっぽくなったかな？', 0, 1, 102301, 'アヤネ', 12, 0, 70);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あ、ぷうきちもお兄ちゃんっぽく\\nなったよね？', 0, 2, 102301, 'アヤネ', 12, 0, 71);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'あなたと出会って、\\nもう1年がたったんですね…\\nこれからもそばにいて、', 0, 1, 104201, 'チカ', 12, 1, 72);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '私のことを見守ってください\\nできることなら、ずっと…', 0, 2, 104201, 'チカ', 12, 1, 73);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'お兄ちゃんと出会って1年かぁ\\n私、相変わらずダメダメで…', 0, 1, 102101, 'クルミ', 12, 2, 74);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'で、でもこれからもずっと…\\n一緒にいたいなぁ…', 0, 2, 102101, 'クルミ', 12, 2, 75);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '再会してちょうど1年だね\\nお祝いにごちそう作ってきたよ～♪\\n特製ケーキと、お寿司と、', 0, 1, 104901, 'シズル', 13, 0, 76);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'ハンバーグと、カレーと、\\nシチューと、あ、隠しきれない隠し\\n味は、お姉ちゃんの愛情だよ！', 0, 2, 104901, 'シズル', 13, 0, 77);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'お兄ちゃんと再会して、もう1年\\nなんですね。\\n会えなかった時を思うと、', 0, 1, 101101, 'リノ', 13, 1, 78);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '信じられないくらい幸せな1年\\nでした！もう絶対、私から離れ\\nないでくださいね♪', 0, 2, 101101, 'リノ', 13, 1, 79);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '騎士クンと出会ってから今まで、\\nいろんなことがあったよね\\n楽しいこと、ドキドキしたこと…', 0, 1, 100201, 'ユイ', 14, 0, 80);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'そんな日々をこれからも、\\nず、ずっと一緒に…\\n過ごしていきたいな…！', 0, 2, 100201, 'ユイ', 14, 0, 81);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '騎士くんと出会って、まだ1年しか\\nたってないんだ！？', 0, 1, 100101, 'ヒヨリ', 14, 1, 82);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'なんかもうずっと一緒にいる気が\\nするなぁ…えへへ。これからの\\n1年もまたよろしくねっ！\\n騎士くん！', 0, 2, 100101, 'ヒヨリ', 14, 1, 83);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '初めてキミに出会って1年…\\n随分見違えたね私もキミも、\\n更に強くなっていく…', 0, 1, 100301, 'レイ', 14, 2, 84);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'キミに背中を預けられる日が、\\n早くきますように', 0, 2, 100301, 'レイ', 14, 2, 85);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '1年もわたしのことを、忘れない\\nでいてくれて、ありがとうござい\\nます！', 0, 1, 105801, 'ペコリーヌ', 15, 0, 86);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'これからもずっと、覚えていて\\nくださいね！', 0, 2, 105801, 'ペコリーヌ', 15, 0, 87);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'こうして1年も、主さまのおそばに\\n置いていただけて、とても光栄\\nです。どうかこれからも、', 0, 1, 105901, 'コッコロ', 15, 1, 88);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '末永く主さまをお世話させて\\nください。わたくしは、ずっと\\n主さまのガイド役でいたいのです', 0, 2, 105901, 'コッコロ', 15, 1, 89);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, '1年か、まっさかこんなに長い\\n付き合いになるなんてね～\\nでも…わりと楽しい1年だったかも', 0, 1, 106001, 'キャル', 15, 2, 90);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80001, 'だから、もうしばらくあんたに\\n付き合ってやるわよ喜びなさい！', 0, 2, 106001, 'キャル', 15, 2, 91);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 1, 60001, '新しい年のはじめに、\\nおみくじはいかがでしょうか？\\nよい運勢であるほど、\\n沢山プレゼントが貰えますよ♪', 0, 1, 112101, 'スズメ', 0, 1, 92);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60001, '今日の運勢は姫吉！\u3000あらゆる運気が最大を示しています！\u3000\u3000\u3000今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！', 0, 0, 0, '', 0, 2, 93);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60001, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0, 0, 0, '', 0, 2, 94);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60001, '今日の運勢は姫吉！\u3000最強の運勢でどんなドジも跳ね除けます！\u3000大切な人と一緒に、最高の一日になること間違いなし！', 0, 0, 0, '', 0, 2, 95);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60001, '今日の運勢は姫吉！\u3000どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！\u3000新しい一歩を踏み出そう！', 0, 0, 0, '', 0, 2, 96);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 2, 60001, '今日の運勢は姫吉！\u3000その高い運気はまさにショーグンの如く！\u3000その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！', 0, 0, 0, '', 0, 2, 97);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60001, '今日の運勢は大吉！\u3000運気がどんどん高まっています！\u3000\u3000\u3000\u3000\u3000何をやっても、最大効率で素晴らしい結果になりますよ♪', 0, 0, 0, '', 0, 2, 98);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60001, '今日の運勢は大吉！\u3000なにをやっても上手くいって大活躍！\u3000\u3000\u3000そんな素敵なあなたを見て、後ろから誰かが……クスクス♪', 0, 0, 0, '', 0, 2, 99);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60001, '今日の運勢は大吉！\u3000ラッキーワードは「ちぇる～ん♪」\u3000\u3000\u3000\u3000出会う人みんなに言ってあげると、ハッピーになれますよ！', 0, 0, 0, '', 0, 2, 100);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60001, '今日の運勢は大吉！\u3000運勢はバッチリで無敵状態！\u3000\u3000\u3000\u3000\u3000\u3000\u3000龍眼で全てを見通して、思い通りの一日を過ごしましょう！', 0, 0, 0, '', 0, 2, 101);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 2, 60001, '今日の運勢は大吉！\u3000運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！\u3000目指せヒデサ……ではなく秀才！', 0, 0, 0, '', 0, 2, 102);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60001, '今日の運勢は中吉！\u3000商売運が上がってきています！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムはたいやき！\u3000和菓子パワーで売上アップです！', 0, 0, 0, '', 0, 2, 103);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60001, '今日の運勢は中吉！\u3000旅行運がぐんぐんと上昇中♪\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、あの「マホマホ王国」にだって行けるかも♪', 0, 0, 0, '', 0, 2, 104);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60001, '今日の運勢は中吉！\u3000仕事運が急上昇中です！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！', 0, 0, 0, '', 0, 2, 105);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60001, '今日の運勢は中吉！\u3000チャンスを待つと良い結果に！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムのプリンを食べて、運を呼び込みましょう！', 0, 0, 0, '', 0, 2, 106);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60001, '今日の運勢は中吉！\u3000お出かけした先で良縁に恵まれそうです！\u3000ダウナー系あざとい女子が、あま～い飴をくれるかも？', 0, 0, 0, '', 0, 2, 107);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60001, '今日の運勢は中吉！\u3000大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！', 0, 0, 0, '', 0, 2, 108);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 2, 60001, '今日の運勢は中吉！\u3000運気が着々と上昇中！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪', 0, 0, 0, '', 0, 2, 109);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60001, '今日の運勢は小吉！\u3000早朝に幸運の兆しあり！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪', 0, 0, 0, '', 0, 2, 110);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60001, '今日の運勢は小吉！\u3000運気上昇中ですが、上がるまでが要注意！\u3000ラッキーアニマルは熊！\u3000本当の家族のように守ってくれるかも♪', 0, 0, 0, '', 0, 2, 111);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60001, '今日の運勢は小吉！\u3000外に出てゆっくり過ごすと運気が上昇！\u3000\u3000ラッキースポットは牧場。面白い出会いがありそうです♪', 0, 0, 0, '', 0, 2, 112);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60001, '今日の運勢は小吉！\u3000運気は高いけども、ハプニングには注意！\u3000出かけた先で、「ふしんしゃ」扱いされてしまうかも……', 0, 0, 0, '', 0, 2, 113);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60001, '今日の運勢は小吉！\u3000同腹一心の友だちが見つかるかも！\u3000\u3000\u3000\u3000キーワードは「ユニちゃんズ」、記憶に刻みましょう！', 0, 0, 0, '', 0, 2, 114);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60001, '今日の運勢は小吉！\u3000思わぬ相手と仲良くなれるかも？\u3000\u3000\u3000\u3000\u3000うっかり毒舌をもらしてしまわないように要注意です！', 0, 0, 0, '', 0, 2, 115);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 2, 60001, '今日の運勢は小吉！\u3000根を詰めずにリラックスすると運気向上！\u3000ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪', 0, 0, 0, '', 0, 2, 116);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60001, 'おみくじの結果はいかがでしたか？\\n新たに始まる一日が、\\nあなたにとってよい日になりますように\\n明日もお待ちしていますね♪', 0, 2, 112101, 'スズメ', 0, 3, 117);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60001, 'おみくじ、楽しんで頂けましたか？\\nあなたの新しい年が\\n素晴らしいものになるよう、\\n心からお祈りしますね', 0, 3, 112101, 'スズメ', 7, 3, 118);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ヒューヒュー♪\\nドンドンパフパフー♪', 0, 1, 105801, 'ペコリーヌ', 1, 0, 119);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ひゅーひゅー\\nどんどんぱふぱふー\\nでございます', 0, 1, 105901, 'コッコロ', 1, 1, 120);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'さぁ、キャルさまもご一緒に\\nどんどんぱふぱふいたしましょう', 0, 2, 105901, 'コッコロ', 1, 1, 121);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'え？\u3000ちょっと\\nいきなりなにっ？', 0, 1, 106001, 'キャル', 1, 2, 122);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ドンドンパフパフってなんなの？\\nあたしにも分かるように\\nちゃんと説明しなさいっての！', 0, 2, 106001, 'キャル', 1, 2, 123);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '実はですねキャルちゃん！\\nもうすぐわたしたちにとっての\\n大切な節目──', 0, 2, 105801, 'ペコリーヌ', 1, 0, 124);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '『プリンセスコネクト！\\nRe:Dive』\\n2.5周年なんですよ！\\nやばいですね☆', 0, 3, 105801, 'ペコリーヌ', 1, 0, 125);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ですからその日に向けて\\n今から気分を盛り上げているのです', 0, 3, 105901, 'コッコロ', 1, 1, 126);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ああ、そういえば\\nそんな時期だっけ\\nって言っても、もう少し先じゃない\\n気が早いんじゃないの？', 0, 3, 106001, 'キャル', 1, 2, 127);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'いいえ、キャルさま\\nこういったお祝いは準備から\\n楽しむものでございます\\nそうですよね、ペコリーヌさま', 0, 4, 105901, 'コッコロ', 1, 1, 128);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'その通りです♪\u3000というわけで！\\nカウントダウンの始まりですよ！\\nみんなで一緒に2.5周年に向けて\\n盛り上がっていきましょー☆', 0, 4, 105801, 'ペコリーヌ', 1, 0, 129);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ド、ドンドンパフパフ～\\nって何言わせんのよ！\\nまったくもう、浮かれちゃってさ', 0, 4, 106001, 'キャル', 1, 2, 130);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ふふ。キャルさまもワクワクして\\nおいでのようですね\\nそれでは主さま。大切な記念日まで\\nどうぞご期待くださいませ', 0, 5, 105901, 'コッコロ', 1, 1, 131);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '記念日を盛り上げるったって\\n一体どうしたらいいのよ？\\nあたし、そういうの\\n苦手なんだけど…', 0, 5, 106001, 'キャル', 2, 0, 132);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あら、キャルさん\\nどうかなさいましたか？\\n何かお困りのようですけど', 0, 1, 190801, 'カリン', 2, 1, 133);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'げっ…カリンじゃない\\nなんでもないわよ！', 0, 6, 106001, 'キャル', 2, 0, 134);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そうなのですか？\\nキャルさんのことですからてっきり\\n2.5周年をどう盛り上げたら\\nいいか悩んでいるのかと…', 0, 2, 190801, 'カリン', 2, 1, 135);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '分かってんじゃないのよ！？\\nいっ、いや、違うけどね！\\nあたしは別にそんなことで\\n悩んでないわよっ？', 0, 7, 106001, 'キャル', 2, 0, 136);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ふふっ…\\nこういう時は、真心を込めて\\n気持ちをそのまま口にしたら\\nいいのではないでしょうか？', 0, 3, 190801, 'カリン', 2, 1, 137);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '気持ちを、ねぇ\\nそれが一番難しいんじゃない…\\nそもそも、あたしは記念日とか\\n別にどうだっていいし', 0, 8, 106001, 'キャル', 2, 0, 138);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '…まあ、ペコリーヌもコロ助も\\nやけに楽しそうだったから…\\nこういうお祭り騒ぎみたいなのも\\nたまにはいいかな、とは思うけど', 0, 9, 106001, 'キャル', 2, 0, 139);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'なるほどなるほど～\\nキャルさんは【美食殿】で祝う\\n2.5周年を心から楽しみに\\nしている、ということですね！', 0, 4, 190801, 'カリン', 2, 1, 140);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'はぁ！？\\nどこ聞いたらそうなるのよ！\\nあたしは別に楽しみになんか…！', 0, 10, 106001, 'キャル', 2, 0, 141);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'キャルさんの心からの想い\\nみなさんにも伝わったでしょうか？\\n私も2.5周年が楽しみです！\\n以上、カリンがお伝えしました！', 0, 5, 190801, 'カリン', 2, 1, 142);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '心からの想いって何なのよ！？\\n勝手に人の言葉を\\n捻じ曲げんじゃないわよ！\\nこのくそ眼鏡ーーーっ！', 0, 11, 106001, 'キャル', 2, 0, 143);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ペコリーヌさま、もうすぐ\\n記念日でございますね\\nこういった節目というのは\\n感慨深いものでございます', 0, 6, 105901, 'コッコロ', 3, 0, 144);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '色んな思い出が蘇ってきますね！\\n楽しい出来事が\\nいっぱいありました♪', 0, 5, 105801, 'ペコリーヌ', 3, 1, 145);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'はい、そうでございますね\\n主さまも【美食殿】の活動の他にも\\nいろんなご経験をされたと\\n聞いておりますよ', 0, 7, 105901, 'コッコロ', 3, 0, 146);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'たしか…ランドソルで話題沸騰と\\nなっていた、魔法少女なるものに\\nお会いになられたとか', 0, 8, 105901, 'コッコロ', 3, 0, 147);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '魔法少女って、あの美味しくって\\n栄養たっぷりの大ヒット商品\\n『魔法少女ソーセージ』の箱に\\n描いてある女の子のことですか！？', 0, 6, 105801, 'ペコリーヌ', 3, 1, 148);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あのソーセージ\\n美味しいんですよね～♪\\nわたしもたっくさん食べてますよ！', 0, 7, 105801, 'ペコリーヌ', 3, 1, 149);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あとは、牧場に素敵な温泉が\\n出来たとか…', 0, 9, 105901, 'コッコロ', 3, 0, 150);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '牧場ですか！？\u3000温泉につかって\\nチーズもオツですね～♪\u3000考えた\\nだけでよだれが出ちゃいそうです！\\nやばいですね☆', 0, 8, 105801, 'ペコリーヌ', 3, 1, 151);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ペコリーヌさま\\n言ってるそばからよだれが…\\n今お拭きしますね。ふき、ふき', 0, 10, 105901, 'コッコロ', 3, 0, 152);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'えへへ、ありがとうございます\\nコッコロちゃん！', 0, 9, 105801, 'ペコリーヌ', 3, 1, 153);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'それにしても、主さまは\\n【美食殿】の一員として様々な\\n美食と出会われていたのですね\\nわたくし、感服いたしました', 0, 11, 105901, 'コッコロ', 3, 0, 154);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'これからもたくさん冒険をして\\nめいっぱい美食を\\n味わい尽くしましょうね！', 0, 10, 105801, 'ペコリーヌ', 3, 1, 155);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '2.5周年カウントダウン♪\\nキャルちゃんキャルちゃん！\\nわくわくしますね☆', 0, 11, 105801, 'ペコリーヌ', 4, 0, 156);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あぁもう、うるさいわね～\\nまだまだ先でしょ？\\nちょっとは落ち着きなさいよ', 0, 12, 106001, 'キャル', 4, 1, 157);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'キャルちゃんだって最近\\nソワソワしてるじゃないですか～\\nさっきもご機嫌そうに鼻歌とか\\n歌ってましたよね？', 0, 12, 105801, 'ペコリーヌ', 4, 0, 158);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'なっ…！\u3000き、聞いてたの！？\\nじゃない、歌ってないわよ！？\\nあんたいい加減なこと言うと\\nぶっ殺すわよ！？', 0, 13, 106001, 'キャル', 4, 1, 159);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'えっへへ～♪\\nわたしは最近のキャルちゃんが\\nもっともっと大好きですよ♪\\nすごく積極的になりましたよね！', 0, 13, 105801, 'ペコリーヌ', 4, 0, 160);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '…積極的？\\nなんの話よ？', 0, 14, 106001, 'キャル', 4, 1, 161);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'またまた～♪\\nアイドルを目指そうとしたこと\\n忘れちゃったんですか？', 0, 14, 105801, 'ペコリーヌ', 4, 0, 162);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ムーサの町で\\nきゃるきゃる～ん☆\u3000って！', 0, 15, 105801, 'ペコリーヌ', 4, 0, 163);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あっ…！？\u3000ちちち違うわよっ！\\nあれは操られてただけで\\nあたしはアイドルなんか\\n目指してないっての！！', 0, 15, 106001, 'キャル', 4, 1, 164);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '本当に本当ですか？\\nわたし、キャルちゃんとっても\\n乗り気だなって\\n思ってたんですけど～', 0, 16, 105801, 'ペコリーヌ', 4, 0, 165);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'まぁ、悪くはなかったけど…って\\nだ、だから目指してないって\\n言ってるでしょ！！\\nなんてこと思い出させんのよ！？', 0, 16, 106001, 'キャル', 4, 1, 166);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ああ…ダメだわ…\\nもう殺すしかない…\\n2.5周年が来る前に\\n記憶ごと消し去ってやるー！', 0, 17, 106001, 'キャル', 4, 1, 167);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '2.5周年まであと10日…\\nふ～ん？\\n案外早いもんね？', 0, 18, 106001, 'キャル', 5, 0, 168);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そうでございますね…\\nその日のためにやるべきことは\\nまだまだございます\\n気を引き締めねばなりません…！', 0, 12, 105901, 'コッコロ', 5, 1, 169);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'やる気十分ねコロ助…\\nそんな気負ってるとしんどいわよ？\\nお気楽にやりましょ？', 0, 19, 106001, 'キャル', 5, 0, 170);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'キャルさま…\\nありがとうございます\\nキャルさまは本当に\\n優しいおかたです', 0, 13, 105901, 'コッコロ', 5, 1, 171);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'な、なにわけの分かんないこと\\n言ってんのよ…\\nあたしは優しくなんかないっての', 0, 20, 106001, 'キャル', 5, 0, 172);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そんなことはございません\\n…あの、実はわたくし\\nキャルさまに\\nひとつお願いがございまして', 0, 14, 105901, 'コッコロ', 5, 1, 173);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'お願い？\u3000珍しいわね\\nコロ助がそんなこと言うなんて\\n…まあ、あたしに出来ることなら\\n別にいいけど', 0, 21, 106001, 'キャル', 5, 0, 174);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ありがとうございます\\n実は記念日へ向けて\\n『かくし芸』というものを\\n用意してみようかと思いまして', 0, 15, 105901, 'コッコロ', 5, 1, 175);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'かくし芸？', 0, 22, 106001, 'キャル', 5, 0, 176);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'はい。きゃるきゃる～ん☆\u3000を\\n参考に、ころころ～ん☆\u3000という\\nご挨拶を考えてみたのですが\\nポーズがうまくいかなくて…', 0, 16, 105901, 'コッコロ', 5, 1, 177);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '～～！！\u3000ちょっと褒められて\\nいい気になって損したわ！！\\nふざけんなふざけんな\\nふ～ざ～け～ん～な～っ！！', 0, 23, 106001, 'キャル', 5, 0, 178);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あと９日！\u3000もうすぐですよ♪\\nえへへ、楽しみで楽しみで\\nごはんが進みますね☆', 0, 17, 105801, 'ペコリーヌ', 6, 0, 179);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ごはんが進みますね☆\\nじゃなーい！\\nいくらなんでも食べ過ぎよ！\\n記念日、迎えられなくなるわよ！？', 0, 24, 106001, 'キャル', 6, 2, 180);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '大丈夫ですよキャルさま\\n食事はわたくしたちの\\n歩んできた道そのもの\\nなのですから', 0, 17, 105901, 'コッコロ', 6, 1, 181);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'さっすがコッコロちゃん\\nいいことを言いますね！\\nそう、わたしたち\\n【美食殿】の活動目的は─', 0, 18, 105801, 'ペコリーヌ', 6, 0, 182);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '─みんなで楽しく食事をすること\\nでしょ？\\nあれだけ食べ歩いてきたんだから\\n分かってるわよ', 0, 25, 106001, 'キャル', 6, 2, 183);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'はい…そうでございますね♪\\nそれにしてもわたくしたち\\n本当にいろいろなものを\\n食べ歩いてきましたね…', 0, 18, 105901, 'コッコロ', 6, 1, 184);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そうね…ほんっとうにね…\\n毒まみれのニセドラゴンとか\\n恐竜…は逃げられちゃったっけ\\nあとワニゴ…ワニの魔物とかね', 0, 26, 106001, 'キャル', 6, 2, 185);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そして、とうとう本物の\\nドラゴンまで相手に\\nしちゃったのよね、あたしたちって', 0, 27, 106001, 'キャル', 6, 2, 186);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '信じられない強さだったわね\\nあのドラゴン…やっぱり\\n作戦はしっかり立てていかないと\\nダメよね', 0, 28, 106001, 'キャル', 6, 2, 187);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'えへへ…☆\\nキャルちゃんが色んなことを\\n覚えていてくれて\\nうれしいです♪', 0, 19, 105801, 'ペコリーヌ', 6, 0, 188);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'わたくしも鮮明に覚えておりますよ\\n主さまもきっと…♪', 0, 19, 105901, 'コッコロ', 6, 1, 189);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あったり前でしょ！\\n忘れないわよ、あんな滅茶苦茶な\\nものばかり食べさせられて！\\n…忘れられるわけ、ないじゃない', 0, 29, 106001, 'キャル', 6, 2, 190);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ねえちょっと、ちょっと待って！？\\nカリンから、2.5周年記念の\\n生放送に出演してほしいって\\n言われたんだけど！', 0, 30, 106001, 'キャル', 7, 0, 191);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'なんでそういう大事なことを\\n急に言うわけ！？\\nそんなの聞いてないわよ～！？', 0, 31, 106001, 'キャル', 7, 0, 192);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'いっぱい人に見られちゃうのよね？\\nなんであたしがそんなこと…', 0, 32, 106001, 'キャル', 7, 0, 193);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あー\\nあー\\n…声、これで大丈夫かしら？', 0, 33, 106001, 'キャル', 7, 0, 194);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '聞き取りにくいかもしれないわね…\\nもうちょっと明るい方がいいかも\\nえっと…こんな感じ？', 0, 34, 106001, 'キャル', 7, 0, 195);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'オイッスー☆', 0, 35, 106001, 'キャル', 7, 0, 196);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '……\\nいや、ないわ\\nいつもどおりが一番ね、うん', 0, 36, 106001, 'キャル', 7, 0, 197);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'もう、記念の生放送なんて\\n超責任重大なやつじゃない…\\nもしなにか失敗とかしたら…', 0, 37, 106001, 'キャル', 7, 0, 198);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ど、どど、どうしよう！？\\n緊張してきちゃった…！！', 0, 38, 106001, 'キャル', 7, 0, 199);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '主さま、わたくし\\nペコリーヌさまとキャルさまと共に\\n2.5周年を祝う生放送に\\n出演する大役を仰せつかりました', 0, 20, 105901, 'コッコロ', 8, 0, 200);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '多くの方々に\\n『プリンセスコネクト！\\nRe:Dive』の魅力をお伝えする\\n重要な役割でございます', 0, 21, 105901, 'コッコロ', 8, 0, 201);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'わたくし、全身全霊をもって\\n生放送に取り組みたいと\\n思っております', 0, 22, 105901, 'コッコロ', 8, 0, 202);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ですが、もしかしたら\\nセリフを噛んでしまったり\\n段取りを間違えてしまったり\\nするかもしれません…', 0, 23, 105901, 'コッコロ', 8, 0, 203);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そのようなことがないよう\\n練習はしっかりしておかなくては\\nまずはこちらから…', 0, 24, 105901, 'コッコロ', 8, 0, 204);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'オイッスー☆', 0, 25, 105901, 'コッコロ', 8, 0, 205);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '先ほどキャルさまが練習されて\\nいるのをお見かけしたので\\nわたくしもと思いまして…\\nいかがでしょうか？', 0, 26, 105901, 'コッコロ', 8, 0, 206);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '良い感じ、ですか？\\n…ふふ、ありがとうございます\\n主さまのあたたかいお言葉があれば\\nわたくしは百人力でございます', 0, 27, 105901, 'コッコロ', 8, 0, 207);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'この大役を無事に成し遂げ\\n主さまに素敵な2.5周年を\\n迎えていただけるよう…\\nわたくし、尽力いたしますね', 0, 28, 105901, 'コッコロ', 8, 0, 208);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'オイッスー☆', 0, 20, 105801, 'ペコリーヌ', 9, 0, 209);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '…う～ん、今のはちょっと\\n違う感じがしますね\\n堅苦しかったかもしれません', 0, 21, 105801, 'ペコリーヌ', 9, 0, 210);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あと６日で2.5周年ですか…', 0, 22, 105801, 'ペコリーヌ', 9, 0, 211);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'この年月がオイッスーの\\n歴史なんだと思うと\\nじ～んとしちゃいます！\\nやばいですね☆', 0, 23, 105801, 'ペコリーヌ', 9, 0, 212);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '生放送で最高のオイッスー☆\u3000を\\nみなさんにお届けするために\\n頑張らないと！\\nそれじゃあもう一度…', 0, 24, 105801, 'ペコリーヌ', 9, 0, 213);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'オイッスー☆', 0, 25, 105801, 'ペコリーヌ', 9, 0, 214);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '…うう～ん、どうしてでしょう\\nまだ何かが違う気がします…\\nもしかしたら\\nおなかが空きすぎてるとか？', 0, 26, 105801, 'ペコリーヌ', 9, 0, 215);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '今さっき食べたばっかりですけど\\nおなかが減っては\\n良いオイッスー☆\u3000は\\n出せませんよね！', 0, 27, 105801, 'ペコリーヌ', 9, 0, 216);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そうと決まれば、コッコロちゃんと\\nキャルちゃんを誘って\\nごはんにしましょう！\\n善は急げです！', 0, 28, 105801, 'ペコリーヌ', 9, 0, 217);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あ、二人が丁度いいところに！\\nオイッス～☆\u3000…ああ！！\\n今の、今のですよ～♪', 0, 29, 105801, 'ペコリーヌ', 9, 0, 218);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'なるほど、どんな時も\\n自然体が一番ってことですね！\\nこの調子で、生放送も\\n頑張っちゃいます♪', 0, 30, 105801, 'ペコリーヌ', 9, 0, 219);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '2.5周年まで残り５日ですが\\nその前にもうすぐ生放送ですよ！\\nコッコロちゃん\\n準備の方はどうですか？', 0, 31, 105801, 'ペコリーヌ', 10, 0, 220);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'はい。わたくし、しっかりと\\n備えてまいりました\\n万事抜かりはございません', 0, 29, 105901, 'コッコロ', 10, 1, 221);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'おお～すごい自信を感じます…！\\nいい生放送になりそうですね☆\\n……あれ？\u3000なんだかこの辺り\\n揺れていませんか？', 0, 32, 105801, 'ペコリーヌ', 10, 0, 222);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '…………', 0, 39, 106001, 'キャル', 10, 2, 223);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'キャルさま？\\nお風邪をひかれたんでしょうか\\nひどい震えですが…', 0, 30, 105901, 'コッコロ', 10, 1, 224);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'かかかか風邪じゃないわよ！\\nここここれはただ\\nななな生放送が楽しみ過ぎて\\nワワワワクワクが止まらないだけ！', 0, 40, 106001, 'キャル', 10, 2, 225);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '大丈夫ですかキャルちゃん！？\\nそうだ、これを飲んでください！', 0, 33, 105801, 'ペコリーヌ', 10, 0, 226);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'きき気がきくじゃない、ありがとっ\\nごくっ、んく…ぶはぁっ！？\\nちょっと何飲ませたの！？\\n辛っ！\u3000苦ぁ！？\u3000甘ぁっ！？', 0, 41, 106001, 'キャル', 10, 2, 227);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'これは魔物のエキスに薬草に\\nその他色んなものを混ぜた\\n特製の栄養ドリンクです！', 0, 34, 105801, 'ペコリーヌ', 10, 0, 228);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'これを飲めば体ぽかぽかで\\n元気いっぱいですよ♪', 0, 35, 105801, 'ペコリーヌ', 10, 0, 229);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'このアホリーヌ！\\n風邪じゃないって言ったでしょ！？\\nどさくさに紛れて\\nそんな恐ろしいもん飲ませんな～！', 0, 42, 106001, 'キャル', 10, 2, 230);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'キャルさま\\n震えが収まっておりますね\\nよかったです…\\nわたくし、心配いたしました', 0, 31, 105901, 'コッコロ', 10, 1, 231);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'え？\u3000ああ、ホントね…って\\nだから風邪じゃないって\\n言ってるのに…\\nまあいいわこの際なんでも', 0, 43, 106001, 'キャル', 10, 2, 232);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'えっへへ～♪\u3000いつも通りの\\nキャルちゃんに戻りましたし\\n素敵な生放送が出来そうですね！\\n今から楽しみです☆', 0, 36, 105801, 'ペコリーヌ', 10, 0, 233);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ランドソルのみなさま、こんにちは\\n生放送の会場設営を担当しています\\n【ギルド管理協会】のカリンです', 0, 6, 190801, 'カリン', 11, 0, 234);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '【美食殿】のみなさんは\\nまもなく始まる生放送に向けて\\n最後の調整のため\\n席を外しています', 0, 7, 190801, 'カリン', 11, 0, 235);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '頑張っている３人の\\n邪魔をするわけには\\nいきませんので、ご容赦ください', 0, 8, 190801, 'カリン', 11, 0, 236);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ですので、本日は私から\\n【美食殿】のみなさんの様子を\\nお伝えさせていただこうと思います', 0, 9, 190801, 'カリン', 11, 0, 237);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'まずはペコリーヌさんですが…\\n何やら大量のおにぎりを\\n食べているようです\\nえっと…栄養は大事ですよね', 0, 10, 190801, 'カリン', 11, 0, 238);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '次にコッコロさんですが\\nこちらは発声練習をしています', 0, 11, 190801, 'カリン', 11, 0, 239);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '一生懸命、小さなお口を開けて\\n声を出す姿が応援したくなりますね', 0, 12, 190801, 'カリン', 11, 0, 240);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そしてキャルさんは…\\nこれは…堂々としたものですね\\n何もせず、ただ立ち尽くして…', 0, 13, 190801, 'カリン', 11, 0, 241);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あれ？\\nもしかして緊張で気を失って…？', 0, 14, 190801, 'カリン', 11, 0, 242);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '…ええと\\n【美食殿】のみなさんは\\nやる気十分なようですね！', 0, 15, 190801, 'カリン', 11, 0, 243);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '３人とも生放送を\\nいいものにしようと\\n全力で頑張ってくれていますので\\nどうかご期待ください', 0, 16, 190801, 'カリン', 11, 0, 244);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'それでは\\nまた明日お会いしましょう♪', 0, 17, 190801, 'カリン', 11, 0, 245);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '2.5周年まであと３日！\\nそして生放送は明日！\\nなんかいよいよって感じね…', 0, 44, 106001, 'キャル', 12, 0, 246);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '３人でい～っぱい練習しましたし\\nきっと大丈夫ですよ☆', 0, 37, 105801, 'ペコリーヌ', 12, 2, 247);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ペコリーヌさまに\\n大丈夫と言ってもらえると\\nとても心強いですね', 0, 32, 105901, 'コッコロ', 12, 1, 248);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '信じすぎちゃだめよコロ助\\nこいつはなーんにも\\n考えてないだけなんだから', 0, 45, 106001, 'キャル', 12, 0, 249);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ひどいですよぉキャルちゃ～ん！', 0, 38, 105801, 'ペコリーヌ', 12, 2, 250);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ふふ。お二人とも\\n普段通りの様子で\\n安心いたしました', 0, 33, 105901, 'コッコロ', 12, 1, 251);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'はいっ☆\\n生放送でもなんでも\\n全力全開、わたしらしく\\nぶつかっていくだけです！', 0, 39, 105801, 'ペコリーヌ', 12, 2, 252);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そうね。おめでたいことなんだし\\nここまで来たんなら\\n楽しめるだけ\\n楽しむしかないわよね！', 0, 46, 106001, 'キャル', 12, 0, 253);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'わたくしも、普段よりも心が\\n熱くなっております\\nこの胸の気持ちをお伝えできるよう\\n精一杯努力いたします…！', 0, 34, 105901, 'コッコロ', 12, 1, 254);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'それでは、いきましょう！\\n明日の生放送、絶対に\\n成功させましょうね☆', 0, 40, 105801, 'ペコリーヌ', 12, 2, 255);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'えっと、最初のひと言は…あれ？\\nキャルちゃん、わたし\\n何て言うんでしたっけ？', 0, 41, 105801, 'ペコリーヌ', 13, 0, 256);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'は！？\\nなにいきなりど忘れしてるの！？\\nっていうかあんた、台本は！？', 0, 47, 106001, 'キャル', 13, 2, 257);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '忘れてきちゃいました☆', 0, 42, 105801, 'ペコリーヌ', 13, 0, 258);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '忘れてきちゃいました☆\\nで済ませられると思ってんの！？\\nほら、あたし二冊持ってきたから\\nこれ使いなさい！', 0, 48, 106001, 'キャル', 13, 2, 259);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'マイクとは、こんな高い位置に\\nあるものなのですね…！\\n背伸びをすれば、何とか…\\nう～ん、うぅ～ん…！', 0, 35, 105901, 'コッコロ', 13, 1, 260);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あぁもう\\n少し下げればいいでしょ！？\\nこれくらいでいい？\\nまったく、世話が焼けるわね…', 0, 49, 106001, 'キャル', 13, 2, 261);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あれ？\\nキャルちゃん、後ろ髪が\\nはねちゃってますよ？', 0, 43, 105801, 'ペコリーヌ', 13, 0, 262);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'え？\u3000うそっ！？\\nちゃんと確かめてきたのに！\\nどこどこ！？', 0, 50, 106001, 'キャル', 13, 2, 263);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'キャルさま、動かないで\\nくださいまし。今くしで…\\nはい、直りましたよ', 0, 36, 105901, 'コッコロ', 13, 1, 264);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あ、ありがと…はぁ。生放送\\n本番までもうすぐなのに\\nこんなことしてる場合じゃ\\nないわよね', 0, 51, 106001, 'キャル', 13, 2, 265);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'はい、時間は残りわずかです\\nですが、慌ただしく\\n動き回るこの時間も\\nなんだか楽しくて…♪', 0, 37, 105901, 'コッコロ', 13, 1, 266);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'コロ助、あんた…って\\nそうじゃなくて！\\n胸にジンワリきてる\\n暇なんかないでしょ…！？', 0, 52, 106001, 'キャル', 13, 2, 267);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あはは♪\\nキャルちゃんの動きが\\nとっても面白いです♪\\nやばいですね☆', 0, 44, 105801, 'ペコリーヌ', 13, 0, 268);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ふふ\\nきっと面白い生放送になると\\nわたくし、確信しております', 0, 38, 105901, 'コッコロ', 13, 1, 269);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '絶対絶対、間違いありません！\\n見てくれるみなさんが\\n笑顔になれる時間を\\nお届けしましょう！', 0, 45, 105801, 'ペコリーヌ', 13, 0, 270);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そんなの当然でしょ！\\n誰が見たって面白いって\\n言ってもらえるように\\nあれだけ準備したんだから！', 0, 53, 106001, 'キャル', 13, 2, 271);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'それでは\\n記念日直前生放送！\\n楽しみにしててくださいね☆', 0, 46, 105801, 'ペコリーヌ', 13, 0, 272);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'こんにちは\\n【ギルド管理協会】のカリンです', 0, 18, 190801, 'カリン', 14, 0, 273);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '昨日の生放送は\\nいかがだったでしょうか？', 0, 19, 190801, 'カリン', 14, 0, 274);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'たくさんの笑顔と喜びと\\nそして驚きを受け取って\\nいただけたのではないかと思います', 0, 20, 190801, 'カリン', 14, 0, 275);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'そしていよいよ\\n明日は2.5周年の当日\\n待ちに待った記念日を\\n迎えることとなります', 0, 21, 190801, 'カリン', 14, 0, 276);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '【美食殿】のみなさんも\\n張り切って様々な準備を\\nされていますよ', 0, 22, 190801, 'カリン', 14, 0, 277);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '【ギルド管理協会】も\\n万全のサポート体制で\\n協力してまいりたいと思います', 0, 23, 190801, 'カリン', 14, 0, 278);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '…ふふ、本当に楽しみですね\\n【ギルド管理協会】の職員として\\nだけではなく、私個人としても…', 0, 24, 190801, 'カリン', 14, 0, 279);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'この記念日を迎えられることが\\n心から楽しみですし\\n幸せを感じています', 0, 25, 190801, 'カリン', 14, 0, 280);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'きっと【美食殿】のみなさんは\\nそれ以上に心を弾ませて\\nいることでしょう', 0, 26, 190801, 'カリン', 14, 0, 281);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'それでは\\n明日からの2.5周年を\\nどうぞ、お楽しみに…♪', 0, 27, 190801, 'カリン', 14, 0, 282);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '準備はいいですかっ？\\n…いっきますよー！', 0, 47, 105801, 'ペコリーヌ', 15, 0, 283);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '祝！', 0, 54, 106001, 'キャル', 15, 2, 284);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '2.5周年！', 0, 39, 105901, 'コッコロ', 15, 1, 285);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'おめでとうございま～す☆', 0, 48, 105801, 'ペコリーヌ', 15, 0, 286);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '少し前まではまだまだ先じゃない\\nとか言ってたけど\\n本当にあっという間だったわね', 0, 55, 106001, 'キャル', 15, 2, 287);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '光陰矢の如し…\\nとはこのことでございますね\\nでも、今日という日を無事に\\n迎えることができて良かったです', 0, 40, 105901, 'コッコロ', 15, 1, 288);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'コッコロちゃん！\u3000キャルちゃん！\\n落ち着くには\\nまだ早いですよ！\\n盛り上がるのはこれからです☆', 0, 49, 105801, 'ペコリーヌ', 15, 0, 289);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ほんとあんたはいつも\\n全力全開ねー\\nでもそうね、記念日なんだし\\nパーっといきましょ！', 0, 56, 106001, 'キャル', 15, 2, 290);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ええ、わたくしも全力全開で\\nまいります…！\\n主さま、さあ\\nどうぞ手を取ってくださいまし…♪', 0, 41, 105901, 'コッコロ', 15, 1, 291);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あんたもコロ助も、浮かれて\\n転ぶんじゃないわよ？\\n…仕方ないから、あたしも\\n手を繋いであげるわよ', 0, 57, 106001, 'キャル', 15, 2, 292);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'あー！\u3000二人ともずるいです！\\nわたしもっ、ギュー♪', 0, 50, 105801, 'ペコリーヌ', 15, 0, 293);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ちょっ、ペコリーヌ！\\nくっつき過ぎよ！', 0, 58, 106001, 'キャル', 15, 2, 294);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '記念日だから\\n平気平気♪\\nやばいですね☆', 0, 51, 105801, 'ペコリーヌ', 15, 0, 295);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '意味分かんないわよ！', 0, 59, 106001, 'キャル', 15, 2, 296);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ふふ。このめでたき日に\\n喜びがあふれておりますね\\n主さまは…いかがでしょうか？', 0, 42, 105901, 'コッコロ', 15, 1, 297);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '喜んでいただけているならば\\nわたくしはとてもとても\\n幸せでございます', 0, 43, 105901, 'コッコロ', 15, 1, 298);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'さぁ、2.5周年を\\n楽しみ尽くしますよ☆\\nまだまだ食べたいものもありますし\\nやりたいこともたくさんです！', 0, 52, 105801, 'ペコリーヌ', 15, 0, 299);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, '分かった、分かったから\\n引っ張るんじゃないわよ！\\n…そんな掴まなくても\\nちゃんとついていくから', 0, 60, 106001, 'キャル', 15, 2, 300);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'ペコリーヌさま…キャルさま…\\n主さま…共にまいりましょう\\nどこまでも…！', 0, 44, 105901, 'コッコロ', 15, 1, 301);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80003, 'はい！\u3000それでは2.5周年\\n食べつくしツアーへ！\\nそして、その先の未来へ\\n向かって出発しましょう！', 0, 53, 105801, 'ペコリーヌ', 15, 0, 302);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('105901,45,106001,61', 0, 0, 80003, '2.5周年\\nありがとうございます！', 1, 54, 105801, 'ペコリーヌ・コッコロ・キャル', 15, 0, 303);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 1, 60002, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0, 1, 190804, 'カリン', 0, 1, 304);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60002, '今日の運勢は姫吉！\u3000どんな不可能も可能にできちゃう！\u3000\u3000\u3000\u3000仲間と食卓を囲めばさらに運気上昇よ！\u3000ただし魔物料理以外！', 0, 0, 0, '', 0, 2, 305);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60002, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0, 0, 0, '', 0, 2, 306);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60002, '今日の運勢は姫吉！\u3000最強の運勢でどんなドジも跳ね除けます！\u3000大切な人と一緒に、最高の一日になること間違いなし！', 0, 0, 0, '', 0, 2, 307);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60002, '今日の運勢は姫吉！\u3000どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！\u3000新しい一歩を踏み出そう！', 0, 0, 0, '', 0, 2, 308);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 2, 60002, '今日の運勢は姫吉！\u3000やること全てが上手くいく最高の一日！\u3000\u3000あなたの活躍に先生もにっこりです。いい子いい子♪', 0, 0, 0, '', 0, 2, 309);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60002, '今日の運勢は大吉！\u3000お裁縫好きな女の子のお墨付きです！\u3000\u3000\u3000お世話したがりの妹にめいっぱい愛されちゃうかも！？', 0, 0, 0, '', 0, 2, 310);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60002, '今日の運勢は大吉！\u3000ラッキーカラーは赤！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000湧き上がるアイデアの数々に、高笑いが止まりませんわ！', 0, 0, 0, '', 0, 2, 311);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60002, '今日の運勢は大吉！\u3000ラッキーワードは「ちぇる～ん♪」\u3000\u3000\u3000\u3000出会う人みんなに言ってあげると、ハッピーになれますよ！', 0, 0, 0, '', 0, 2, 312);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60002, '今日の運勢は大吉！\u3000運勢はバッチリで無敵状態！\u3000\u3000\u3000\u3000\u3000\u3000\u3000龍眼で全てを見通して、思い通りの一日を過ごしましょう！', 0, 0, 0, '', 0, 2, 313);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 2, 60002, '今日の運勢は大吉！\u3000悩んでいたことが解決しそうです！\u3000\u3000\u3000\u3000たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！', 0, 0, 0, '', 0, 2, 314);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60002, '今日の運勢は中吉！\u3000家の中でゆっくり過ごすのがよさそう！\u3000\u3000ラッキーアイテムはゲームよ！\u3000ベストスコアを更新できるかも？', 0, 0, 0, '', 0, 2, 315);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60002, '今日の運勢は中吉！\u3000上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？', 0, 0, 0, '', 0, 2, 316);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60002, '今日の運勢は中吉！\u3000仕事運が急上昇中です！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！', 0, 0, 0, '', 0, 2, 317);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60002, '今日の運勢は中吉！\u3000日頃の努力が報われます！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。', 0, 0, 0, '', 0, 2, 318);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60002, '今日の運勢は中吉！\u3000商売運が上がってきています！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムはたい焼き！\u3000和菓子パワーで売上アップです！', 0, 0, 0, '', 0, 2, 319);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60002, '今日の運勢は中吉！\u3000チャンスを待つと良い結果に！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムのプリンを食べて、運を呼び込みましょう！', 0, 0, 0, '', 0, 2, 320);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 2, 60002, '今日の運勢は中吉！\u3000運気が着々と上昇中！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000精霊の加護を受けたかのごとく、色々な事がうまくいきますよ♪', 0, 0, 0, '', 0, 2, 321);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60002, '今日の運勢は小吉！\u3000まだ見ぬ危険が隠れているかも！\u3000\u3000\u3000\u3000\u3000でも安心しろ！\u3000提督が貴公を守ってくれるはずだぞ！', 0, 0, 0, '', 0, 2, 322);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60002, '今日の運勢は小吉！\u3000いろんな事件が起こる一日になりそう！\u3000\u3000状況をよく観察してみようじゃないか！\u3000まさに探偵のごとくね！', 0, 0, 0, '', 0, 2, 323);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60002, '今日の運勢は小吉！\u3000気の向くままに過ごすのが幸せへの近道！\u3000美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？', 0, 0, 0, '', 0, 2, 324);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60002, '今日の運勢は小吉！\u3000運気は高いけども、ハプニングには注意！\u3000出かけた先で、「ふしんしゃ」扱いされてしまうかも……', 0, 0, 0, '', 0, 2, 325);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60002, '今日の運勢は小吉！\u3000同腹一心の友だちが見つかるかも！\u3000\u3000\u3000\u3000キーワードは「ユニちゃんズ」、記憶に刻みましょう！', 0, 0, 0, '', 0, 2, 326);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60002, '今日の運勢は小吉！\u3000周りに流されず、マイペースな一日を！\u3000\u3000ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～', 0, 0, 0, '', 0, 2, 327);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 2, 60002, '今日の運勢は小吉！\u3000根を詰めずにリラックスすると運気向上！\u3000ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪', 0, 0, 0, '', 0, 2, 328);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60002, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0, 2, 190804, 'カリン', 0, 3, 329);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60002, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0, 3, 190804, 'カリン', 7, 3, 330);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ささ、シェフィさまはこちらへ…', 0, 1, 105901, 'コッコロ', 1, 4, 331);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'コッコロさん、どこへ行くの…？\\n…え？', 0, 1, 106401, 'シェフィ', 1, 0, 332);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '『おめでとうございます！\\nわ～パチパチー！』\\n…という感じでどうですかね！？', 0, 1, 105801, 'ペコリーヌ', 1, 3, 333);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ではわたくしも\\n後ろからクラッカーを鳴らして\\n応戦いたします\\nああ、当日が待ち遠しいですね', 0, 2, 105901, 'コッコロ', 1, 4, 334);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ええと…\\n二人とも何をしているの？', 0, 2, 106401, 'シェフィ', 1, 0, 335);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'シェフィは初めてだもんね\\nあの日が近いからって\\n予行練習してんのよ\\n気が早いわよね～', 0, 1, 106001, 'キャル', 1, 1, 336);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'あの日…？', 0, 3, 106401, 'シェフィ', 1, 0, 337);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'その通りです…\\nいよいよ記念すべきあの日が\\n近づいてきましたよ！', 0, 2, 105801, 'ペコリーヌ', 1, 3, 338);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '『プリンセスコネクト！\\nRe:Dive』3.5周年！', 0, 3, 105801, 'ペコリーヌ', 1, 3, 339);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'やばいですね☆', 0, 1, 190801, 'カリン', 1, 2, 340);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'って、なにしれっと\\n参加してんのよカリン！', 0, 2, 106001, 'キャル', 1, 1, 341);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ふふ、いいじゃないですか\\n【ギルド管理協会】として\\n私もみなさんと一緒に\\nお祝いをさせてください！', 0, 2, 190801, 'カリン', 1, 2, 342);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それに…記念日が近づけば\\nとっておきの情報を\\nお届けしますから♪', 0, 3, 190801, 'カリン', 1, 2, 343);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'というわけで\\n今日からシェフィちゃんも一緒に\\nカウントダウンしちゃいましょう！\\n3.5周年まで…', 0, 4, 105801, 'ペコリーヌ', 1, 3, 344);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'えっ！？\u3000ええとええと…！\\nあ、あと14日…！', 0, 4, 106401, 'シェフィ', 1, 0, 345);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと13日\\n豪華に、そして盛大に\\nお祝いしたいですね☆', 0, 5, 105801, 'ペコリーヌ', 2, 3, 346);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '豪華といえば前にとある貴族さまが\\n舞踏会を開かれたそうで\\n主さまがそのお手伝いを\\nしておりました', 0, 3, 105901, 'コッコロ', 2, 1, 347);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'そこで美しい所作を学ばれたので\\nわたくしも教えていただきました\\nしゃなり、しゃなり…\\nいかがでしょう？', 0, 4, 105901, 'コッコロ', 2, 1, 348);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'すっごく上手ですよ☆\\nまるでお姫様みたいです\\nせっかくなのでわたしも\\nしゃなりしゃなり', 0, 6, 105801, 'ペコリーヌ', 2, 3, 349);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'さすがでございます\\nペコリーヌさま', 0, 5, 105901, 'コッコロ', 2, 1, 350);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'いや、あんたは\\nできなきゃダメでしょ\\n本物のお姫様なんだし', 0, 3, 106001, 'キャル', 2, 0, 351);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'しゃなり、しゃなり…\\nふふ、案外できるものね', 0, 5, 106401, 'シェフィ', 2, 2, 352);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'わぁ！\\nシェフィちゃん\\n姿勢がとってもキレイです♪', 0, 7, 105801, 'ペコリーヌ', 2, 3, 353);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'さ、次はキャルさまの\\n番でございますよ', 0, 6, 105901, 'コッコロ', 2, 1, 354);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'あ、あたしはいいわよ！\\nそういうの全然分かんないし…', 0, 4, 106001, 'キャル', 2, 0, 355);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '大丈夫\\nやってみると結構楽しいわよ\\nほらほらっ', 0, 6, 106401, 'シェフィ', 2, 2, 356);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'そ、そこまで言うなら…\\nしゃなにゅわきゃあっ！', 0, 5, 106001, 'キャル', 2, 0, 357);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'いたたた…もぉお～！\\nなんであたしがこんな目に～！', 0, 6, 106001, 'キャル', 2, 0, 358);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'まぁまぁ\\n記念日までに練習すれば\\nできるようになるかもしれません\\nよろしければお教えいたしますよ', 0, 7, 105901, 'コッコロ', 2, 1, 359);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'よし！\\nあんたたちができて\\nあたしだけできないのはしゃくだし\\nやってやろうじゃないの！！', 0, 7, 106001, 'キャル', 2, 0, 360);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと12日\\n記念日当日はもちろんですが\\nその日を待つ時間というのも\\n心躍ります', 0, 8, 105901, 'コッコロ', 3, 1, 361);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '分かりますっ！\\nどんな特別な料理を食べられるのか\\n考えるだけでワクワクしますよね！', 0, 8, 105801, 'ペコリーヌ', 3, 3, 362);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '特別な料理といえば、お祭りですね\\nそういえば主さまは学生として\\n聖学祭に参加されたこと\\nがあるとか…', 0, 9, 105901, 'コッコロ', 3, 1, 363);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '聖学祭…って、なにかしら？', 0, 7, 106401, 'シェフィ', 3, 2, 364);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '聖テレサ女学院の祭典ですよ\\n二つのチームが競い合い\\n青春を満喫するのが趣旨のようです', 0, 10, 105901, 'コッコロ', 3, 1, 365);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それってカルミナの\\nサプライズライブがあった\\nお祭りよね？\\nちょっと見たかったかも…', 0, 8, 106001, 'キャル', 3, 0, 366);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'カルミナの後の\\nライブも好評だったらしいじゃない\\n確か、なかよし部\\nだったっけ…？', 0, 9, 106001, 'キャル', 3, 0, 367);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'なかよし部…\\n仲が良さそうな名前で\\nやばいですね☆', 0, 9, 105801, 'ペコリーヌ', 3, 3, 368);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'いや、そのまんますぎでしょ…', 0, 10, 106001, 'キャル', 3, 0, 369);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '聖学祭かぁ…なんだか楽しそうね\\nそれになかよし部の人たちも\\n気になるわ', 0, 8, 106401, 'シェフィ', 3, 2, 370);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それじゃあわたしたちも、\\n負けじと仲良くしましょう♪\\nほらほらシェフィちゃん、\\nぎゅーっ☆\u3000ですよ♪', 0, 10, 105801, 'ペコリーヌ', 3, 3, 371);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'えっ？\u3000ええ…\\nぎゅーっ…？', 0, 9, 106401, 'シェフィ', 3, 2, 372);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと11日！？\\nお祝いの準備進んでないんだけど…\\nああ～昨日に戻りたいわ…', 0, 11, 106001, 'キャル', 4, 0, 373);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'そういえばそんな魔道具があるって\\n聞いたことがあるわね\\n確か、名前はタイムラーベ…', 0, 10, 106401, 'シェフィ', 4, 2, 374);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'なにそれヤバいわね\\nでも本当にあるんだったら\\n準備よりももっとやり直したいこと\\nたくさんあるんだけど…', 0, 12, 106001, 'キャル', 4, 0, 375);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'もしや正月の件でしょうか…？\\nあの時はお金がなくて\\n苦労しましたから', 0, 11, 105901, 'コッコロ', 4, 1, 376);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'あれはそうね…\\nお金を湯水のように使う\\nぺコリーヌを止められたら\\nあんな苦労をすることもなかったし', 0, 13, 106001, 'キャル', 4, 0, 377);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'そんなこともありましたね！\\nやり直したいといえば\\n『きゃるきゃる～ん♪』\\nの方かと思いましたよ！', 0, 11, 105801, 'ペコリーヌ', 4, 3, 378);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'バラすんじゃないわよ\\nこのアホリーヌ！\\nシェフィはそれ\\n知らないんだから！', 0, 14, 106001, 'キャル', 4, 0, 379);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'こうなったらもう、なんとか\\nタイムラーべを探し出して\\n今の会話をなかったことに…\\nって、どうしたのよシェフィ', 0, 15, 106001, 'キャル', 4, 0, 380);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'うん…もし、私だったら…\\n私が知らないみんなとの時間を\\n見てみたいな、って…', 0, 11, 106401, 'シェフィ', 4, 2, 381);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'シェフィちゃん！\u3000タイムなんとか\\nなんかなくても大丈夫ですよ！\\n一緒の時間はこれから\\nどんどん作ればいいんですから！', 0, 12, 105801, 'ペコリーヌ', 4, 3, 382);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'はい、今この瞬間も\\n未来にはかけがえのない思い出に\\nなっていることでしょう', 0, 12, 105901, 'コッコロ', 4, 1, 383);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'だからそんな顔しないの\\nほら、お祝いの準備、進めるわよ！', 0, 16, 106001, 'キャル', 4, 0, 384);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'みんな…そうね\\n最高のお祝いにして\\n最高の思い出にしましょう！', 0, 12, 106401, 'シェフィ', 4, 2, 385);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まで、あと10日！\\nもうすぐですよー！\\n楽しみすぎて、やばいですね！', 0, 13, 105801, 'ペコリーヌ', 5, 3, 386);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'そういえば…たくさんのおもちゃが\\n子どもたちを襲うっていう\\n騒動もありましたね…\\nなんでも勝手に動き出したとか！', 0, 14, 105801, 'ペコリーヌ', 5, 3, 387);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '学校や孤児院とかに\\nちっちゃなおもちゃが乗り込んで\\n暴れたみたいですよ！', 0, 15, 105801, 'ペコリーヌ', 5, 3, 388);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '暴れたって言っても\\n所詮はおもちゃじゃない\\nどうせちっさいんでしょ？', 0, 17, 106001, 'キャル', 5, 0, 389);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'だったら魔法で\\n全部ぶっ飛ばせばいいじゃない！\\n大したことないわよ！', 0, 18, 106001, 'キャル', 5, 0, 390);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'キャルってば…\\n相手は子どもが\\n大事にしてる物なのよ…？', 0, 13, 106401, 'シェフィ', 5, 2, 391);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '乱暴な発言は\\nめっ、でございますよ？\\n子どもの教育に悪影響を\\n与えてしまいますから…', 0, 13, 105901, 'コッコロ', 5, 1, 392);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'キャルちゃんだって\\n意外と猫グッズとか\\nたっくさん集めてますよね？\\nもしその子たちが暴れたら…？', 0, 16, 105801, 'ペコリーヌ', 5, 3, 393);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'う、うっさいわね！\\n意外とか言うな！\\n…ま、まあ確かに正面切って\\n魔法でぶっ飛ばせないかもね…', 0, 19, 106001, 'キャル', 5, 0, 394);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'あはは☆\\nキャルちゃんのそういうところ\\n好きですよ♪', 0, 17, 105801, 'ペコリーヌ', 5, 3, 395);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'そんなキャルちゃんに猫グッズを\\nプレゼントしちゃいますね！\\n一部で流行っていた、たい焼き屋の\\nおまけフィギュアですよ♪', 0, 18, 105801, 'ペコリーヌ', 5, 3, 396);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '乱暴に扱ったりしないでくださいね\\nひとりでに暴れ出しちゃうかも\\nしれませんから！', 0, 19, 105801, 'ペコリーヌ', 5, 3, 397);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと９日\\nここでみなさんに\\nビックニュースですよ！', 0, 4, 190801, 'カリン', 6, 2, 398);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年を祝う生放送に\\n去年と同様【美食殿】の\\nみなさんにご出演いただくことが\\n決定しましたー！', 0, 5, 190801, 'カリン', 6, 2, 399);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…えっ！？', 0, 20, 106001, 'キャル', 6, 1, 400);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '本当ですか！？\\nそれじゃ今から張り切って\\n生放送中に食べる魔物料理を\\n作らなくちゃですね☆', 0, 20, 105801, 'ペコリーヌ', 6, 3, 401);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'いや…がんばるところは\\nそこじゃないような…\\nというか去年も出演してたのね\\nすごいじゃない！', 0, 14, 106401, 'シェフィ', 6, 0, 402);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'はい。とても緊張しますが\\nやりがいのある大役です\\n一緒にがんばりましょうね\\nシェフィさま', 0, 14, 105901, 'コッコロ', 6, 4, 403);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'わ、私も出るの！？\u3000でも…\\n私も【美食殿】の一人だものね\\nそれなら今からしっかり準備をして\\nコンディションを整えないと…', 0, 15, 106401, 'シェフィ', 6, 0, 404);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ふふん♪\\n生放送直前のカチコチになった\\nシェフィの姿が楽しみだわ！', 0, 21, 106001, 'キャル', 6, 1, 405);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '去年のキャルちゃんは\\n緊張しすぎてずっと震えて\\nかわいかったですもんね！\\n今年もあの姿が見たいです！', 0, 21, 105801, 'ペコリーヌ', 6, 3, 406);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ぶっ殺すぞ！？', 0, 22, 106001, 'キャル', 6, 1, 407);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'というわけで\\n『プリンセスコネクト！\\nRe:Dive』の魅力を\\nお伝えする生放送をお楽しみに♪', 0, 6, 190801, 'カリン', 6, 2, 408);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと８日\\nでございますよ\\n楽しみですね、主さま', 0, 15, 105901, 'コッコロ', 7, 1, 409);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'そういえばあんた\\n夏休みの宿題は\\nきちんとやってるの？', 0, 23, 106001, 'キャル', 7, 0, 410);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '宿題…学校に通うのも\\n楽しいことばかりじゃ\\nないのね', 0, 16, 106401, 'シェフィ', 7, 2, 411);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'あれ？\u3000そういえば\\n少し前にルーセント学院で\\n何かあったような…', 0, 22, 105801, 'ペコリーヌ', 7, 3, 412);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ああ、始業式の日に\\n大捕り物があったって\\n話題になってたわね', 0, 24, 106001, 'キャル', 7, 0, 413);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '夏休みを終わらせないって\\n騒いでたっていう話？\\nあれ本当なの？\\n都市伝説だと思ってたわ', 0, 17, 106401, 'シェフィ', 7, 2, 414);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'その一件ならよく存じ上げて\\nおります。ですから主さま\\n次の機会にはわたくしと一緒に\\nがんばりましょう', 0, 16, 105901, 'コッコロ', 7, 1, 415);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '楽しそう…私も一緒にやりたいな\\nママ…じゃ、じゃなくて！\\nコッコロさん、私もまざっていい？', 0, 18, 106401, 'シェフィ', 7, 2, 416);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'もちろんでございます\\n仲良くお勉強いたしましょう', 0, 17, 105901, 'コッコロ', 7, 1, 417);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'しれっと教育ママが\\n生まれてる…？', 0, 25, 106001, 'キャル', 7, 0, 418);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'お勉強は大切ですよ！\\nキャルちゃんも一緒に\\nがんばりましょう！', 0, 23, 105801, 'ペコリーヌ', 7, 3, 419);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'え～～～～！？', 0, 26, 106001, 'キャル', 7, 0, 420);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと７日〜♪\\nふふ～ん♪\\nふんふふ～ん♪', 0, 27, 106001, 'キャル', 8, 0, 421);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…\\nねぇコッコロさん\\nキャル、どうしちゃったの？', 0, 19, 106401, 'シェフィ', 8, 2, 422);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'とてもご機嫌そうに\\n鼻歌を歌ってらっしゃいますね\\n耳も尻尾もリズミカルに\\n揺れて…ノリノリでございます', 0, 18, 105901, 'コッコロ', 8, 1, 423);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'あれはですね！\\nカルミナのみなさんの\\nサマーライブのチケットが\\n手に入ったからなんですよ♪', 0, 24, 105801, 'ペコリーヌ', 8, 3, 424);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ええっ！？\\nあのライブのチケットって確か\\n入手困難だったんじゃ…', 0, 20, 106401, 'シェフィ', 8, 2, 425);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ふふふふ～ん♪\\nしゃいにんぐふゅ～ちゃ～♪', 0, 28, 106001, 'キャル', 8, 0, 426);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'なるほど…\\nキャルさまがあのように\\nなってしまうのも頷けますね', 0, 19, 105901, 'コッコロ', 8, 1, 427);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…カルミナの\\n『Shining Future』\\nの中に、シャイニングフューチャー\\nって歌詞はなかったはずだけど…', 0, 21, 106401, 'シェフィ', 8, 2, 428);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ふんふ…はっ！？\\nあっ、あんたたち！\\nなに人の鼻歌を\\n勝手に聞いてるのよ！？', 0, 29, 106001, 'キャル', 8, 0, 429);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'こっ、これは別に\\nカルミナの曲じゃなくて…\\nあたしのオリジナルソングよ！\\n聞いたらお金取るわよっ！？', 0, 30, 106001, 'キャル', 8, 0, 430);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'えへへ、キャルちゃん\\nカルミナのサマーライブ\\n思いっきり楽しみましょうね☆', 0, 25, 105801, 'ペコリーヌ', 8, 3, 431);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'も～っ！\\n生暖かい目で見るな～～！\\nぶっ殺すわよ～～～！', 0, 31, 106001, 'キャル', 8, 0, 432);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと６日\\n３人も言ってたけど\\nあっという間だったわね', 0, 22, 106401, 'シェフィ', 9, 0, 433);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…えっ？\\n生放送の意気込み！？\\n突然なに！？', 0, 23, 106401, 'シェフィ', 9, 0, 434);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ええと…\\nとにかく失敗しないように\\n台本たくさん読んで…\\nそれから…', 0, 24, 106401, 'シェフィ', 9, 0, 435);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'えっ！？\\nトラブルがあったら\\nどうするのかって！？\\nそ、それは…！', 0, 25, 106401, 'シェフィ', 9, 0, 436);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'とにかく落ち着いて\\nスタッフさんの指示を聞いて…', 0, 26, 106401, 'シェフィ', 9, 0, 437);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それから、それから…！\\nぅ、ぅぅっ…！', 0, 27, 106401, 'シェフィ', 9, 0, 438);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '―びえぇぇ～んっ！！！', 0, 28, 106401, 'シェフィ', 9, 0, 439);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'どうされましたか、シェフィさま', 0, 20, 105901, 'コッコロ', 9, 1, 440);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ううっ…ひっく…\\nママッ…！', 0, 29, 106401, 'シェフィ', 9, 0, 441);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'よしよし、緊張されてるのですね\\nママが傍におりますよ\\n主さま、少々お待ちくださいませ', 0, 21, 105901, 'コッコロ', 9, 1, 442);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…ふぅ\\nシェフィさま\\n生放送への意気込み\\nお話しできそうですか？', 0, 22, 105901, 'コッコロ', 9, 1, 443);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…ううっ\\n恥ずかしすぎて\\nもう生放送出られない…', 0, 30, 106401, 'シェフィ', 9, 0, 444);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '主さま\\n3.5周年まであと５日\\nでございます', 0, 23, 105901, 'コッコロ', 10, 0, 445);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ですがその前に\\n生放送がありますね', 0, 24, 105901, 'コッコロ', 10, 0, 446);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…生放送に向けた\\n意気込みでございますか？', 0, 25, 105901, 'コッコロ', 10, 0, 447);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'もちろんわたくしは\\n主さまのために\\n全身全霊を込めて\\n楽しい時間をご提供いたします', 0, 26, 105901, 'コッコロ', 10, 0, 448);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…と、意気込んでみましたが\\nうまくできるか少し不安です\\n声が小さくなったり\\n間違えてしまったらどうしようと…', 0, 27, 105901, 'コッコロ', 10, 0, 449);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ですがわたくしは\\n一人ではありません\\n【美食殿】のみなさまが\\nおります', 0, 28, 105901, 'コッコロ', 10, 0, 450);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'どんな困難も\\nみなさまと一緒なら\\n乗り越えられると\\nわたくし、確信しております', 0, 29, 105901, 'コッコロ', 10, 0, 451);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それに今回はシェフィさまも\\nご参加されるわけですし\\nママとしてお手本に\\nならねばなりませんね', 0, 30, 105901, 'コッコロ', 10, 0, 452);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '主さま。3.5周年も\\n食卓を囲んでいる時のような\\n楽しい思い出を\\n一緒に作りましょうね', 0, 31, 105901, 'コッコロ', 10, 0, 453);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと４日！\\nやばいですね☆', 0, 26, 105801, 'ペコリーヌ', 11, 0, 454);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'はいはい、やばいわね\\nというかもうすぐ生放送だけど\\nあんた準備はできてるの？', 0, 32, 106001, 'キャル', 11, 1, 455);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ばっちりオイッスー☆\u3000ですよ！\\n『王家の装備』も全開です！', 0, 27, 105801, 'ペコリーヌ', 11, 0, 456);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'あとは前回を超える\\n最高のオイッスー☆\u3000を\\nお届けできるように\\n練習あるのみですかね！', 0, 28, 105801, 'ペコリーヌ', 11, 0, 457);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'キャルちゃんは\\nどうなんですか？\\nオイッスー☆\u3000を\\n毎日ちゃんと練習してますか？', 0, 29, 105801, 'ペコリーヌ', 11, 0, 458);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'はぁ！？\u3000なんであたしまで\\nその変なあいさつを練習しないと\\nいけないのよ！', 0, 33, 106001, 'キャル', 11, 1, 459);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'もしかしてやってないんですか？\\nダメですよキャルちゃん！\\nシェフィちゃんだってちゃんと\\n毎日練習してるのに！', 0, 30, 105801, 'ペコリーヌ', 11, 0, 460);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'こうなったらわたしがキャルちゃん\\nにオイッスー☆\u3000の『オ』から\\nしっかり教えてあげないと！', 0, 31, 105801, 'ペコリーヌ', 11, 0, 461);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'オイッスー☆\u3000の『オ』は\\n口を大きく開いて〜\\nドラゴンの骨つき肉に\\nかぶりつく直前をイメージして〜', 0, 32, 105801, 'ペコリーヌ', 11, 0, 462);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'だからあたしはやるなんて一言も…', 0, 34, 106001, 'キャル', 11, 1, 463);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'オイッスー☆', 0, 33, 105801, 'ペコリーヌ', 11, 0, 464);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '聞きなさいっての！！', 0, 35, 106001, 'キャル', 11, 1, 465);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと３日…\\nそして生放送は、明日…', 0, 31, 106401, 'シェフィ', 12, 2, 466);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'もっと台本を\\n読み込んでおかないと…\\nあと発声練習も…', 0, 32, 106401, 'シェフィ', 12, 2, 467);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'おいっす！\\n…こうじゃなかったわね\\nええと確か…', 0, 33, 106401, 'シェフィ', 12, 2, 468);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'うう…あんなに練習したのに\\nこれじゃみんなに迷惑かけちゃう…', 0, 34, 106401, 'シェフィ', 12, 2, 469);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '【美食殿】の一員として\\n認められるように\\n頑張らないといけないのに\\nよし、もう一度…', 0, 35, 106401, 'シェフィ', 12, 2, 470);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'やってますねシェフィちゃん！', 0, 34, 105801, 'ペコリーヌ', 12, 3, 471);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'なによ、考えることは\\nみんな同じってこと？', 0, 36, 106001, 'キャル', 12, 0, 472);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ふふ。シェフィさま\\nよろしければ\\n仲間に入れてください\\n一緒にやればきっとうまくできます', 0, 32, 105901, 'コッコロ', 12, 1, 473);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'みんな…もちろんよ！', 0, 36, 106401, 'シェフィ', 12, 2, 474);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それじゃ明日の生放送に向けて\\n一緒に練習がんばりましょう☆', 0, 35, 105801, 'ペコリーヌ', 12, 3, 475);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年まであと２日と\\n迫った本日は…\\nいよいよ生放送です！', 0, 7, 190801, 'カリン', 13, 2, 476);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '【美食殿】のみなさんが\\n準備に入られていますので\\nそれぞれ繋いでみましょう！\\nまずはペコリーヌさんです！', 0, 8, 190801, 'カリン', 13, 2, 477);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '今日もオイッスー☆\\nみんなで一緒に\\nオイッスー☆', 0, 36, 105801, 'ペコリーヌ', 13, 3, 478);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'お手本になるような\\n発声練習ですね！\\nそれでは続いてコッコロさん', 0, 9, 190801, 'カリン', 13, 2, 479);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'はじめちょろちょろ\\nなかぱっぱ～♪\\n生放送前にみなさまで\\n食卓を囲んで英気を養いましょう', 0, 33, 105901, 'コッコロ', 13, 4, 480);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'さすが【美食殿】のママですね！\\nそしてキャルさんは…', 0, 10, 190801, 'カリン', 13, 2, 481);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '大丈夫…大丈夫…\\nあたしは大丈夫…', 0, 37, 106001, 'キャル', 13, 1, 482);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'す、すごく震えてますけど\\n大丈夫でしょうか…？\\nそして今回初参加となる\\n期待の新人シェフィさん！', 0, 11, 190801, 'カリン', 13, 2, 483);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'あうー？', 0, 37, 106401, 'シェフィ', 13, 0, 484);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('105901,34,106001,38,190801,12', 0, 0, 80005, 'あ…', 1, 37, 105801, 'みんな', 13, 4, 485);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ちょ、ちょっとシェフィ！？\\nなに赤ちゃん返りしてん―\\nあ痛ぁっ！\\n噛んだわこいつーっ！', 0, 39, 106001, 'キャル', 13, 1, 486);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'シェフィさま\\n緊張しすぎて\\nしまったのでしょうね…\\nおーよしよし…', 0, 35, 105901, 'コッコロ', 13, 4, 487);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'シェフィちゃん！\\nそういう時は手のひらに\\n好きな文字を書いて\\n食べちゃうといいですよ！', 0, 38, 105801, 'ペコリーヌ', 13, 3, 488);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '…ええと、現場からは以上です！\\n生放送はもうすぐ！\\n特別なお知らせもありますので\\nどうぞお楽しみに！', 0, 13, 190801, 'カリン', 13, 2, 489);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年の記念日も\\nいよいよ明日ね\\n…って、あれ？', 0, 38, 106401, 'シェフィ', 14, 2, 490);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '記念日はこの森へ行きませんか！？\\nすっごく美味しいお肉が\\nとれるんです☆', 0, 39, 105801, 'ペコリーヌ', 14, 3, 491);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'うげ、またあの魔物？\\nさすがに今度は\\n丸焼きとかはやめてよね…\\n見た目がヤバすぎるし', 0, 40, 106001, 'キャル', 14, 0, 492);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ふふ、キャルさまもだいぶ\\n魔物肉に慣れてきたようですね\\n調理ならばわたくしに\\nお任せください♪', 0, 36, 105901, 'コッコロ', 14, 1, 493);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'みんな、何をしているの？\\nなんだか、\\n不穏な単語が聞こえたんだけど…', 0, 39, 106401, 'シェフィ', 14, 2, 494);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'シェフィちゃん！\\n明日の食べ尽くしツアーの\\n相談をしてたんですよ！', 0, 40, 105801, 'ペコリーヌ', 14, 3, 495);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'はい。明日は【美食殿】の\\n一員となったシェフィさまと一緒に\\n初めて記念日を過ごすのですから\\n特別なコース料理を用意しませんと', 0, 37, 105901, 'コッコロ', 14, 1, 496);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ふふん♪\\n猫の毛も逆立つような\\nあれこれを食べさせられるから\\n覚悟しておいたほうがいいわよ？', 0, 41, 106001, 'キャル', 14, 0, 497);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'へ、へぇ…', 0, 40, 106401, 'シェフィ', 14, 2, 498);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '期待しててくださいね！\\nシェフィちゃんとあなたに\\n『おいちー！』って喜んでもらえる\\n最高のごちそうを準備しますから☆', 0, 41, 105801, 'ペコリーヌ', 14, 3, 499);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ええと…その…うーんと…\\nわ、分かったわ\\n私も【美食殿】の一員だもの', 0, 41, 106401, 'シェフィ', 14, 2, 500);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それにあなたも一緒みたいだし\\n最後までがんばってみるわ…！', 0, 42, 106401, 'シェフィ', 14, 2, 501);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それではいつものあれを\\nやりましょう！\\n準備はいいですかっ？\\n…いっきますよー！', 0, 42, 105801, 'ペコリーヌ', 15, 3, 502);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '祝！', 0, 42, 106001, 'キャル', 15, 1, 503);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '3.5周年！', 0, 38, 105901, 'コッコロ', 15, 4, 504);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'おめでとうございます！', 0, 43, 106401, 'シェフィ', 15, 0, 505);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'この日を迎えられたのも\\nあなたが『プリンセスコネクト！\\nRe:Dive』を遊んでくれている\\nおかげです！', 0, 14, 190801, 'カリン', 15, 2, 506);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ということで\\nみなさんからあなたへ一言ずつ\\n感謝の言葉をどうぞ！', 0, 15, 190801, 'カリン', 15, 2, 507);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '感謝の言葉ですか？\u3000わたしは\\n毎日あなたに感謝してますよ\\n【美食殿】の仲間になってくれて…\\n一緒にごはんを食べてくれて…', 0, 43, 105801, 'ペコリーヌ', 15, 3, 508);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'なにより今でもわたしをぺコリーヌ\\nって呼んでくれてありがとうござい\\nます。これからもわたしはあなたの\\nぺコリーヌです！\u3000やばいですね☆', 0, 44, 105801, 'ペコリーヌ', 15, 3, 509);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'えっ！？\u3000今度はあたし！？\\n感謝って…まぁ、そうね…\\nあんたにはあたしが\\n辛くて苦しい時に助けてもらって…', 0, 43, 106001, 'キャル', 15, 1, 510);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'でもおかげで色々吹っ切れたわ！\\nもしあんたが困ってたら今度は\\nあたしが助けてあげるから\\nその時はちゃんと言いなさいよ！', 0, 44, 106001, 'キャル', 15, 1, 511);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ええと…次は私ね\\n実はよく覚えてないのだけど\\n空から落ちてきた私を受け止めて\\nくれたのはあなたなのでしょう？', 0, 44, 106401, 'シェフィ', 15, 0, 512);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, '最初に私を見つけてくれたのが\\nあなたで良かったって思ってるの\\nおかげで私は居場所を見つけたから\\nあなたがくれたもの、大切にするわ', 0, 45, 106401, 'シェフィ', 15, 0, 513);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'では最後にわたくしから…\\nわたくしは主さまの元を離れた日…\\nこのように記念日をお祝いする\\nことは二度とないと思っていました', 0, 39, 105901, 'コッコロ', 15, 4, 514);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'ですが、主さまはわたくしを\\n迎えにきてくださり、今もこうして\\nおそばにおいてくださっています\\nわたくしにとって毎日が記念日です', 0, 40, 105901, 'コッコロ', 15, 4, 515);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'わたくしたちの物語は\\nまだ続いていきます\\nこれからも一緒にページを\\n作っていきましょうね', 0, 41, 105901, 'コッコロ', 15, 4, 516);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 80005, 'それじゃ\\nいつものあれでしめますよ！\\nみんなで一緒に、さんはい☆', 0, 45, 105801, 'ペコリーヌ', 15, 3, 517);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('105901,42,106001,45,106401,46,190801,16', 0, 0, 80005, 'これからも\\nよろしくおねがいします！', 1, 46, 105801, 'みんな', 15, 4, 518);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 1, 60003, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0, 1, 190804, 'カリン', 0, 1, 519);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60003, '今日の運勢は姫吉！\u3000どんな不可能も可能にできちゃう！\u3000\u3000\u3000\u3000仲間と食卓を囲めばさらに運気上昇よ！\u3000ただし魔物料理以外！', 0, 0, 0, '', 0, 2, 520);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60003, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0, 0, 0, '', 0, 2, 521);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60003, '今日の運勢は姫吉！\u3000羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！\u3000やってみましょう！', 0, 0, 0, '', 0, 2, 522);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60003, '今日の運勢は姫吉！\u3000精霊も新年の幸福をお祝いしています！\u3000\u3000主さまの笑顔が見られて、わたくしも幸せいっぱいでございます♪', 0, 0, 0, '', 0, 2, 523);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 2, 60003, '今日の運勢は姫吉！\u3000やること全てが上手くいく最高の一日！\u3000\u3000あなたの活躍に先生もにっこりです。いい子いい子♪', 0, 0, 0, '', 0, 2, 524);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60003, '今日の運勢は大吉！\u3000お裁縫好きな女の子のお墨付きです！\u3000\u3000\u3000お世話したがりの妹にめいっぱい愛されちゃうかも！？', 0, 0, 0, '', 0, 2, 525);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60003, '今日の運勢は大吉！\u3000ラッキーカラーは赤！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000湧き上がるアイデアの数々に、高笑いが止まりませんわ！', 0, 0, 0, '', 0, 2, 526);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60003, '今日の運勢は大吉！\u3000ラッキーカラーは鮮やかな黄色！\u3000\u3000\u3000\u3000\u3000さらにシマシマのアイテムを持つと、運気倍増らしいッスよ♪', 0, 0, 0, '', 0, 2, 527);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60003, '今日の運勢は大吉！\u3000秘められた力が開花するでしょう！\u3000\u3000\u3000\u3000じゃあ、私の龍眼と力比べしてみようか？\u3000ふふ、冗談だよ～', 0, 0, 0, '', 0, 2, 528);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 2, 60003, '今日の運勢は大吉！\u3000悩んでいたことが解決しそうです！\u3000\u3000\u3000\u3000たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！', 0, 0, 0, '', 0, 2, 529);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60003, '今日の運勢は中吉！\u3000家の中でゆっくり過ごすのがよさそう！\u3000\u3000ラッキーアイテムはゲームよ！\u3000ベストスコアを更新できるかも？', 0, 0, 0, '', 0, 2, 530);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60003, '今日の運勢は中吉！\u3000上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？', 0, 0, 0, '', 0, 2, 531);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60003, '今日の運勢は中吉！\u3000仕事運が急上昇中です！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！', 0, 0, 0, '', 0, 2, 532);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60003, '今日の運勢は中吉！\u3000日頃の努力が報われます！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。', 0, 0, 0, '', 0, 2, 533);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60003, '今日の運勢は中吉！\u3000ラッキーアイテムはかわいいもの！\u3000\u3000\u3000\u3000ア、アタシはかわいいじゃなくてキレイだってば！\u3000も～っ！', 0, 0, 0, '', 0, 2, 534);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60003, '今日の運勢は中吉！\u3000チャンスを待つと良い結果に！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムのプリンを食べて、運を呼び込みましょう！', 0, 0, 0, '', 0, 2, 535);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 2, 60003, '今日の運勢は中吉！\u3000悩まず行動すれば強運に恵まれる！\u3000\u3000\u3000\u3000守るよりも攻めるが吉だ！\u3000勝負事をするにはいい運勢だな！', 0, 0, 0, '', 0, 2, 536);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60003, '今日の運勢は小吉！\u3000まだ見ぬ危険が隠れているかも！\u3000\u3000\u3000\u3000\u3000でも安心しろ！\u3000提督が貴公を守ってくれるはずだぞ！', 0, 0, 0, '', 0, 2, 537);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60003, '今日の運勢は小吉！\u3000いろんな事件が起こる一日になりそう！\u3000\u3000状況をよく観察してみようじゃないか！\u3000まさに探偵のごとくね！', 0, 0, 0, '', 0, 2, 538);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60003, '今日の運勢は小吉！\u3000気の向くままに過ごすのが幸せへの近道！\u3000美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？', 0, 0, 0, '', 0, 2, 539);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60003, '今日の運勢は小吉！\u3000難しい頼み事をされるかもしれません！\u3000\u3000うまくやれればきっと成長につながります、挑戦してみましょう！', 0, 0, 0, '', 0, 2, 540);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60003, '今日の運勢は小吉！\u3000同腹一心の友だちが見つかるかも！\u3000\u3000\u3000\u3000キーワードは「ユニちゃんズ」、記憶に刻みましょう！', 0, 0, 0, '', 0, 2, 541);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60003, '今日の運勢は小吉！\u3000周りに流されず、マイペースな一日を！\u3000\u3000ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～', 0, 0, 0, '', 0, 2, 542);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 2, 60003, '今日の運勢は小吉！\u3000無理は禁物、お家で静かにしていましょう\u3000プロぼっちの私が、お家での過ごし方……教えてあげましょうか？', 0, 0, 0, '', 0, 2, 543);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60003, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0, 2, 190804, 'カリン', 0, 3, 544);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60003, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0, 3, 190804, 'カリン', 7, 3, 545);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 1, 60004, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0, 1, 190804, 'カリン', 0, 1, 546);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60004, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0, 0, 0, '', 0, 2, 547);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60004, '今日の運勢は姫吉！\u3000羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！\u3000やってみましょう！', 0, 0, 0, '', 0, 2, 548);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60004, '今日の運勢は姫吉！\u3000宴でも開きたくなるほどの絶対幸運！\\nイメチェンでもしてみるのはどうだ？\u3000ぴょんぴょん、なんてな♪', 0, 0, 0, '', 0, 2, 549);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60004, '今日の運勢は姫吉！\u3000ずっと祈り続けていた願いが叶うかも！\\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に', 0, 0, 0, '', 0, 2, 550);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60004, '今日の運勢は姫吉！\u3000やること全てが上手くいく最高の一日！\u3000\u3000あなたの活躍に先生もにっこりです。いい子いい子♪', 0, 0, 0, '', 0, 2, 551);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60004, '今日の運勢は大吉！\u3000悩んでいたことが解決しそうです！\u3000\u3000\u3000\u3000たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！', 0, 0, 0, '', 0, 2, 552);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 2, 60004, '今日の運勢は大吉！\u3000ラッキーカラーは赤！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000湧き上がるアイデアの数々に、高笑いが止まりませんわ！', 0, 0, 0, '', 0, 2, 553);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60004, '今日の運勢は大吉！\u3000ラッキーワードは「ぴょんぴょん♪」\\nおっきな声で一緒に言ってみよ～♪\u3000うさぎさんぴょんぴょ～ん♪', 0, 0, 0, '', 0, 2, 554);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60004, '今日の運勢は大吉！\u3000あなたの趣味がもっと広がるかも！\\nかんわゆ～～～いショタと～騎士きゅんもゲット～んふふ～♪', 0, 0, 0, '', 0, 2, 555);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60004, '今日の運勢は大吉！\u3000秘められた力が開花するでしょう！\u3000\u3000\u3000\u3000じゃあ、私の龍眼と力比べしてみようか？\u3000ふふ、冗談だよ～', 0, 0, 0, '', 0, 2, 556);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60004, '今日の運勢は中吉！\u3000ラッキーアイテムはかわいいもの！\u3000\u3000\u3000\u3000ア、アタシはかわいいじゃなくてキレイだってば！\u3000も～っ！', 0, 0, 0, '', 0, 2, 557);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 2, 60004, '今日の運勢は中吉！\u3000悩まず行動すれば強運に恵まれる！\u3000\u3000\u3000\u3000守るよりも攻めるが吉だ！\u3000勝負事をするにはいい運勢だな！', 0, 0, 0, '', 0, 2, 558);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60004, '今日の運勢は中吉！\u3000お出かけした先で良縁に恵まれそうです！\u3000ダウナー系あざとい女子が、あま～い飴をくれるかも？', 0, 0, 0, '', 0, 2, 559);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60004, '今日の運勢は中吉！\u3000大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！', 0, 0, 0, '', 0, 2, 560);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60004, '今日の運勢は中吉！\u3000健康に気を遣って気持ちのいい一年を！\\n体に不調があるときは遠慮なく言いなさい、隅々まで調べてあげる', 0, 0, 0, '', 0, 2, 561);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60004, '今日の運勢は中吉！\u3000歌を口ずさみ、幸運を呼び込もう！\\n幸運になれるかは分からないけど……一緒に、歌いましょ？', 0, 0, 0, '', 0, 2, 562);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60004, '今日の運勢は中吉！\u3000誰かに尽くすことで掴める幸せもあるかも？\\n人事を尽くして天命を待つ！\u3000さ、年始もバリバリ働きますわよ♪', 0, 0, 0, '', 0, 2, 563);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60004, '今日の運勢は小吉！\u3000難しい頼み事をされるかもしれません！\u3000\u3000うまくやれればきっと成長につながります、挑戦してみましょう！', 0, 0, 0, '', 0, 2, 564);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60004, '今日の運勢は小吉！\u3000無理は禁物、お家で静かにしていましょう\u3000プロぼっちの私が、お家での過ごし方……教えてあげましょうか？', 0, 0, 0, '', 0, 2, 565);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60004, '今日の運勢は小吉！\u3000思わぬ相手と仲良くなれるかも？\u3000\u3000\u3000\u3000\u3000うっかり毒舌をもらしてしまわないように要注意です！', 0, 0, 0, '', 0, 2, 566);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 2, 60004, '今日の運勢は小吉！\u3000いろんな事件が起こる一日になりそう！\u3000\u3000状況をよく観察してみようじゃないか！\u3000まさに探偵のごとくね！', 0, 0, 0, '', 0, 2, 567);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60004, '今日の運勢は小吉！\u3000周りに流されず、マイペースな一日を！\u3000\u3000ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～', 0, 0, 0, '', 0, 2, 568);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60004, '今日の運勢は小吉！\u3000気の向くままに過ごすのが幸せへの近道！\u3000美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？', 0, 0, 0, '', 0, 2, 569);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 2, 60004, '今日の運勢は小吉！\u3000小さな勇気で踏み出す一歩が大事！\\n遠くから見てるだけじゃダメ。今日は、少しだけ近づいてみます！', 0, 0, 0, '', 0, 2, 570);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60004, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0, 2, 190804, 'カリン', 0, 3, 571);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60004, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0, 3, 190804, 'カリン', 7, 3, 572);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 1, 60005, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0, 1, 190804, 'カリン', 0, 1, 573);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60005, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0, 0, 0, '', 0, 2, 574);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 1, 60005, '今日の運勢は姫吉！\u3000ずっと祈り続けていた願いが叶うかも！\\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に', 0, 0, 0, '', 0, 2, 575);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 2, 60005, '今日の運勢は姫吉！\u3000道を歩けば幸運に当たる、最高の吉日！\u3000\u3000さすがは兄様。尽善尽美、金甌無欠の強運をお持ちですね。', 0, 0, 0, '', 0, 2, 576);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 2, 60005, '今日の運勢は姫吉！\u3000旅立ち、どこへ行くもよし！\u3000\u3000\u3000\u3000\u3000\u3000\u3000新年の門出も、お兄さんと一緒です♪\u3000冒険にしゅっぱーつ♪', 0, 0, 0, '', 0, 2, 577);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 1, 2, 60005, '今日の運勢は姫吉！\u3000一日三食食べれば健康運アップ！\u3000\u3000\u3000\u3000\u3000おせち。おぞうに。もっと、たべよ？\u3000お兄。', 0, 0, 0, '', 0, 2, 578);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60005, '今日の運勢は大吉！\u3000あなたの趣味がもっと広がるかも！\\nかんわゆ～～～いショタと～騎士きゅんもゲット～んふふ～♪', 0, 0, 0, '', 0, 2, 579);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60005, '今日の運勢は大吉！\u3000お裁縫好きな女の子のお墨付きです！\u3000\u3000\u3000お世話したがりの妹にめいっぱい愛されちゃうかも！？', 0, 0, 0, '', 0, 2, 580);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 1, 60005, '今日の運勢は大吉！\u3000日々の努力が実り、何事も良い方向へ！\u3000\u3000そんな弟くんには、お姉ちゃんのよしよしぎゅ～っをプレゼント♪', 0, 0, 0, '', 0, 2, 581);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 2, 60005, '今日の運勢は大吉！\u3000お出かけするといいことあるかも？\u3000\u3000\u3000\u3000また一緒に、お忍びデートしてくださいね……騎士♪', 0, 0, 0, '', 0, 2, 582);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 2, 2, 60005, '今日の運勢は大吉！\u3000転居するならあたたかい場所が吉！\u3000\u3000\u3000\u3000煉獄の世なれど、住めば都と申しんす。ゆるりときなんせ……♪', 0, 0, 0, '', 0, 2, 583);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60005, '今日の運勢は中吉！\u3000大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！', 0, 0, 0, '', 0, 2, 584);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60005, '今日の運勢は中吉！\u3000誰かに尽くすことで掴める幸せもあるかも？\\n人事を尽くして天命を待つ！\u3000さ、年始もバリバリ働きますわよ♪', 0, 0, 0, '', 0, 2, 585);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60005, '今日の運勢は中吉！\u3000歌を口ずさみ、幸運を呼び込もう！\\n幸運になれるかは分からないけど……一緒に、歌いましょ？', 0, 0, 0, '', 0, 2, 586);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60005, '今日の運勢は中吉！\u3000健康に気を遣って気持ちのいい一年を！\\n体に不調があるときは遠慮なく言いなさい、隅々まで調べてあげる', 0, 0, 0, '', 0, 2, 587);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 1, 60005, '今日の運勢は中吉！\u3000旅行運がぐんぐんと上昇中♪\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、あの「マホマホ王国」にだって行けるかも♪', 0, 0, 0, '', 0, 2, 588);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 2, 60005, '今日の運勢は中吉！\u3000争いごとは勝つが油断は大敵！\u3000\u3000\u3000\u3000\u3000\u3000ま、このあたしと一緒なら、向かうところ敵はねーですよっ！', 0, 0, 0, '', 0, 2, 589);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 3, 2, 60005, '今日の運勢は中吉！\u3000ラッキーアイテムは「光るもの」！\u3000\u3000\u3000\u3000ハツネちゃんの「きらーんっ☆」な魔法、見せちゃおうかなっ？', 0, 0, 0, '', 0, 2, 590);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60005, '今日の運勢は小吉！\u3000のんびり穏やかな一日となるでしょう！\u3000\u3000あなた様を邪魔するものは全てエリコが排除しますわ、クスクス♪', 0, 0, 0, '', 0, 2, 591);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60005, '今日の運勢は小吉！\u3000小さな勇気で踏み出す一歩が大事！\\n遠くから見てるだけじゃダメ。今日は、少しだけ近づいてみます！', 0, 0, 0, '', 0, 2, 592);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60005, '今日の運勢は小吉！\u3000外に出てゆっくり過ごすと運気が上昇！\u3000\u3000ラッキースポットは牧場。面白い出会いがありそうです♪', 0, 0, 0, '', 0, 2, 593);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60005, '今日の運勢は小吉！\u3000いろんな事件が起こる一日になりそう！\u3000\u3000状況をよく観察してみようじゃないか！\u3000まさに探偵のごとくね！', 0, 0, 0, '', 0, 2, 594);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 1, 60005, '今日の運勢は小吉！\u3000難しい頼み事をされるかもしれません！\u3000\u3000うまくやれればきっと成長につながります、挑戦してみましょう！', 0, 0, 0, '', 0, 2, 595);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 2, 60005, '今日の運勢は小吉！\u3000空を眺めると気持ちが晴れやかに！\u3000\u3000\u3000\u3000眺めるだけじゃなくて、ひとっ飛びしちゃいましょうかっ♪', 0, 0, 0, '', 0, 2, 596);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 4, 2, 60005, '今日の運勢は小吉！\u3000掃除をすると運勢が開けそう！\u3000\u3000\u3000\u3000\u3000\u3000「わ、めんど」「ヴルムっ！\u3000新年早々サボっちゃダメなんだからね！」', 0, 0, 0, '', 0, 2, 597);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60005, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0, 2, 190804, 'カリン', 0, 3, 598);
insert into v1_1dafa53cc6a20fee857dff813f6ed1a8ee08c18a93cbbf5e2eb05aed29cbeac8 values ('', 0, 0, 60005, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0, 3, 190804, 'カリン', 7, 3, 599);
